INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Âme', 'Demon', 'Ressource', NULL, 0, NULL, NULL, 'Commune', NULL, 'Ajoute 1 Âme à votre réserve. Vous ne pouvez jouer qu''une ressource par tour.', 'Une clause parmi tant d''autres. Elle aussi se paiera.', '/assets/card_art/resource/demon-resource.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Éclat d''Anomalie', 'Abomination', 'Ressource', NULL, 0, NULL, NULL, 'Commune', NULL, 'Ajoute 1 Anomalie à ta réserve Abomination. Une seule carte-ressource par tour et par camp.', 'Ça continue de battre, même détaché de tout le reste.', '/assets/card_art/resource/abomination-resource.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Chair', 'Mort-Vivant', 'Ressource', NULL, 0, NULL, NULL, 'Commune', NULL, 'Ajoute 1 Chair à votre réserve. Vous ne pouvez jouer qu''une ressource par tour.', 'Ce qui reste d''une vie, cristallisé par la nécromancie.', '/assets/card_art/resource/undead-resource.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Sceau du Royaume', 'Humain', 'Ressource', NULL, 0, NULL, NULL, 'Commune', NULL, 'Ajoute 1 Sceau à ta réserve Humaine. Une seule carte-ressource peut être posée par tour.', 'Frappé au nom du roi, il lie chaque soldat à son serment.', '/assets/card_art/resource/human-resource.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Murmure Funeste', 'Mort-Vivant', 'Enchantement', NULL, 1, NULL, NULL, 'Rare', NULL, 'Présence : le premier Mort-Vivant joué chaque tour coûte 1 de moins (min 1).', 'On ne l''entend pas. On sent juste que quelque chose a dit oui.', '/assets/card_art/undead/doomed-whisper.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Rampant en Décomposition', 'Mort-Vivant', 'Serviteur', 'Avant', 1, 1, 1, 'Commune', NULL, 'Dernier Souffle : invoque un Zombie 1/1 sous ton contrôle.', 'Il ne sait plus pourquoi il avance. Il avance, c''est tout.', '/assets/card_art/undead/decaying-crawler.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Souffle Corrupteur', 'Demon', 'Incantation', NULL, 1, NULL, NULL, 'Commune', NULL, 'Un serviteur ennemi ciblé perd 1 ATK de façon permanente (Corruption).', 'Un murmure suffit. Le reste se fait tout seul, avec le temps.', '/assets/card_art/demon/grand-corrupter.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Larve Cadavérique', 'Mort-Vivant', 'Serviteur', 'Hybride', 1, 1, 1, 'Commune', NULL, 'NÉCROPHAGE : gagne +1/+1 de façon permanente quand un serviteur allié meurt.', 'Elle n''est pas née de la vie. Elle est née de ce qui reste.', '/assets/card_art/undead/cadaverous-larva.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Souffle du Charnier', 'Mort-Vivant', 'Incantation', NULL, 1, NULL, NULL, 'Commune', NULL, 'Un Mort-Vivant allié ciblé gagne +0/+2.', 'Ce qui ne peut pas mourir davantage peut encore endurcir.', '/assets/card_art/undead/breath-of-the-charnel-house.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Premier Tressaut', 'Abomination', 'Incantation', NULL, 1, NULL, NULL, 'Commune', NULL, 'Un serviteur allié ciblé déclenche immédiatement une mutation.', 'Il n''a pas eu le temps de choisir. Peu importe.', '/assets/card_art/abomination/first-twitch.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Pacte Hâtif', 'Demon', 'Incantation', NULL, 1, NULL, NULL, 'Commune', NULL, 'Ton héros perd 2 HP ; pioche 2 cartes.', 'Signer vite coûte cher. Signer tard coûte pareil.', '/assets/card_art/demon/hasty-pact.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Repli Tactique', 'Humain', 'Incantation', NULL, 1, NULL, NULL, 'Commune', NULL, 'Déplace un serviteur allié de la rangée Avant vers la rangée Arrière (ou inversement). Il conserve ses effets.', 'Reculer n''est pas fuir. C''est choisir où mourir.', '/assets/card_art/human/tactical-retreat.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Larve Infernale', 'Demon', 'Serviteur', 'Avant', 1, 2, 1, 'Commune', NULL, 'PACTE.', 'Elle ne demande rien. Elle prend juste sa part avant même d''arriver.', '/assets/card_art/demon/hellspawn-larva.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Éclaireur Rapide', 'Humain', 'Serviteur', 'Avant', 1, 1, 1, 'Commune', NULL, 'ASSAUT. Arrivée : pioche 1 carte si la rangée Avant ennemie a 3 serviteurs ou plus.', 'Il revient toujours avec de mauvaises nouvelles. Il revient, c''est ce qui compte.', '/assets/card_art/human/swift-scout.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Amas Informe', 'Abomination', 'Serviteur', 'Avant', 1, 1, 2, 'Commune', NULL, 'MUTATION.', 'Il n''a pas de nom parce qu''il n''a pas encore de forme.', '/assets/card_art/abomination/formless-mass.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Doigt Écarlate', 'Demon', 'Incantation', NULL, 1, NULL, NULL, 'Rare', NULL, 'Pioche 1 carte. Ton héros perd 1 HP. Si c''est un Démon, il coûte 1 de moins ce tour.', 'Il désigne. Ce qu''il montre a toujours un prix, y compris pour toi.', '/assets/card_art/demon/judge-of-the-damned.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Emprunt Instantané', 'Abomination', 'Incantation', NULL, 1, NULL, NULL, 'Commune', NULL, 'Un serviteur allié ciblé copie un mot-clé présent sur un autre serviteur en jeu tiré au hasard (allié ou ennemi).', 'Il n''a rien inventé. Il a juste regardé, et pris.', '/assets/card_art/abomination/instant-borrowing.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Cri de Ralliement', 'Humain', 'Incantation', NULL, 1, NULL, NULL, 'Commune', NULL, 'Humains alliés +0/+1 jusqu''à fin de tour.', 'Un seul cri. Toute la ligne se souvient pourquoi elle est là.', '/assets/card_art/human/rally-cry.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Invocateur Novice', 'Demon', 'Serviteur', 'Hybride', 1, 1, 1, 'Commune', NULL, 'PACTE.', 'Son premier pacte. Il ne sait pas encore combien ça va coûter, au fil du temps.', '/assets/card_art/demon/novice-summoner.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Milicien du Bourg', 'Humain', 'Serviteur', 'Avant', 1, 2, 1, 'Commune', NULL, 'Dernier Souffle : invoque un Éclaireur Rapide 1/1.', 'Il est tombé en gardant la route ouverte. C''est tout ce qu''il avait demandé.', '/assets/card_art/human/town-militiaman.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Bouclier de Foi', 'Humain', 'Incantation', NULL, 1, NULL, NULL, 'Rare', NULL, 'Donne ÉGIDE à un serviteur Humain allié ciblé jusqu''à fin du prochain tour adverse.', 'La foi ne rend pas invulnérable. Elle donne juste le temps d''encaisser le premier coup.', '/assets/card_art/human/faith-shield.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Conscrit', 'Humain', 'Serviteur', 'Avant', 1, 1, 2, 'Commune', NULL, NULL, 'Il n''a pas choisi de venir. Il est venu quand même.', '/assets/card_art/human/conscript.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Goule Affamée', 'Mort-Vivant', 'Serviteur', 'Avant', 1, 2, 1, 'Commune', NULL, 'NÉCROPHAGE : gagne +1/+1 de façon permanente quand un serviteur allié meurt.', 'La faim ne disparaît pas avec la mort. Elle empire.', '/assets/card_art/undead/famished-ghoul.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Doigt Décharné', 'Mort-Vivant', 'Incantation', NULL, 1, NULL, NULL, 'Rare', NULL, 'Pioche 1 carte. Si c''est un Mort-Vivant, il coûte 1 de moins ce tour.', 'Il désigne. Quelque chose, quelque part, répond.', '/assets/card_art/undead/gaunt-finger.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Chuchotement Qui Change la Forme', 'Abomination', 'Enchantement', NULL, 1, NULL, NULL, 'Rare', NULL, 'Présence : la première Abomination jouée chaque tour coûte 1 de moins (min 1).', 'On ne l''entend pas. On sent juste que quelque chose a déjà commencé à changer.', '/assets/card_art/abomination/shapeshifting-whisper.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Respir Qui Change Tout', 'Abomination', 'Incantation', NULL, 1, NULL, NULL, 'Commune', NULL, '1 dégât à tous les serviteurs en jeu ; les Abominations alliées touchées mutent à la place de perdre des HP.', 'Même tes alliés changent, un peu, à chaque respiration.', '/assets/card_art/abomination/all-changing-breath.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Exhalation Toxique', 'Mort-Vivant', 'Incantation', NULL, 1, NULL, NULL, 'Commune', NULL, '1 dégât à tous les serviteurs en jeu.', 'Même ses alliés évitent de respirer trop près.', '/assets/card_art/undead/toxic-exhalation.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Réveil Soudain', 'Mort-Vivant', 'Incantation', NULL, 1, NULL, NULL, 'Commune', NULL, 'Ressuscite le dernier serviteur allié mort avec 1 HP en rangée Avant.', 'Il n''y a pas de repos pour ceux qu''on rappelle.', '/assets/card_art/undead/sudden-awakening.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Signe Qui Répond', 'Abomination', 'Incantation', NULL, 1, NULL, NULL, 'Rare', NULL, 'Pioche 1 carte. Si c''est une Abomination, elle coûte 1 de moins ce tour.', 'Il désigne. Quelque chose répond, déjà changé.', '/assets/card_art/abomination/answering-sign.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Suppôt des Abysses', 'Demon', 'Serviteur', 'Avant', 1, 1, 2, 'Commune', NULL, 'CORRUPTION.', 'Une simple morsure, et déjà quelque chose s''effrite en toi.', '/assets/card_art/demon/abyssal-thrall.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Semence Amère', 'Abomination', 'Serviteur', 'Hybride', 1, 1, 1, 'Commune', NULL, 'VIRULENT.', 'Elle n''attend pas d''être plantée. Elle éclate là où elle tombe.', '/assets/card_art/abomination/bitter-seed.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Cœur Sans Corps', 'Abomination', 'Serviteur', 'Hybride', 1, 2, 1, 'Commune', NULL, 'ASSIMILATION.', 'Il bat pour quelque chose qui n''existe plus.', '/assets/card_art/abomination/bodiless-heart.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Locataire Sans Bail', 'Abomination', 'Serviteur', 'Hybride', 2, 1, 2, 'Rare', NULL, 'FUSION.', 'Il ne demande jamais la permission de s''installer dans un autre corps.', '/assets/card_art/abomination/uninvited-tenant.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Chuchoteur Malin', 'Demon', 'Serviteur', 'Hybride', 2, 2, 2, 'Commune', NULL, 'Arrivée : ton héros perd 1 HP ; pioche 1 carte.', 'Il murmure une vérité. Elle a toujours un prix.', '/assets/card_art/demon/whisperfiend.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Le Reste-Qui-Veille', 'Abomination', 'Serviteur', 'Avant', 2, 1, 4, 'Rare', NULL, 'REMPART. ASSIMILATION.', 'Il grandit à chaque garde tombée, la sienne comme celle d''en face.', '/assets/card_art/abomination/watching-remnant.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Étreinte du Gouffre', 'Demon', 'Incantation', NULL, 2, NULL, NULL, 'Commune', NULL, 'Gèle un serviteur ennemi ciblé un tour ; ton héros perd 1 HP.', 'Le froid des Abysses n''épargne personne, pas même celui qui l''invoque.', '/assets/card_art/demon/abyssal-grasp.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Garde Infernal', 'Demon', 'Serviteur', 'Avant', 2, 1, 4, 'Rare', NULL, 'REMPART. Dernier Souffle : ton héros perd 1 HP ; invoque une Larve Infernale 2/1.', 'Il ne meurt jamais vraiment seul. Quelque chose se lève toujours après lui.', '/assets/card_art/demon/infernal-warden.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Flamme Infernale', 'Demon', 'Incantation', NULL, 2, NULL, NULL, 'Commune', NULL, '2 dégâts à un serviteur ennemi ciblé ; ton héros perd 1 HP.', 'Le feu ne fait pas de distinction. Il te lèche un peu au passage.', '/assets/card_art/demon/infernal-flame.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Chasseur des Abysses', 'Demon', 'Serviteur', 'Avant', 2, 3, 2, 'Rare', NULL, 'CORRUPTION.', 'Il ne tue pas toujours. Parfois, il préfère laisser pourrir.', '/assets/card_art/demon/abyssal-stalker.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Larve Ascendante', 'Demon', 'Serviteur', 'Hybride', 2, 1, 2, 'Rare', NULL, 'RANG INFERNAL.', 'Elle grandit dans les cicatrices, pas dans la lumière.', '/assets/card_art/demon/ascending-hellspawn.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Gargouille de Cendres', 'Demon', 'Serviteur', 'Arriere', 2, 1, 3, 'Commune', NULL, 'REMPART. CHAIR DE SOUFRE.', 'Elle a regardé brûler des cathédrales entières sans ciller.', '/assets/card_art/demon/ashen-gargoyle.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Sangsue Infernale', 'Demon', 'Serviteur', 'Avant', 2, 2, 2, 'Commune', NULL, 'Arrivée : ton héros regagne 2 HP.', 'Elle ne mord jamais l''ennemi en premier. Elle commence toujours par toi, doucement.', '/assets/card_art/demon/hellleech.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Rite de Sang', 'Demon', 'Incantation', NULL, 2, NULL, NULL, 'Rare', NULL, 'Sacrifice (un serviteur allié) : ton héros regagne 3 HP ; inflige 3 dégâts au héros ennemi.', 'Un sang pour un autre. L''échange est rarement équitable — sauf pour toi, cette fois.', '/assets/card_art/demon/blood-rite.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Communion Écarlate', 'Demon', 'Incantation', NULL, 2, NULL, NULL, 'Commune', NULL, 'Ton héros regagne 3 HP ; pioche 1 carte.', 'Le pacte n''est pas qu''une dette. Parfois, il rembourse.', '/assets/card_art/demon/crimson-communion.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Emprise Écarlate', 'Demon', 'Incantation', NULL, 2, NULL, NULL, 'Rare', NULL, 'Prend le contrôle d''un serviteur ennemi ayant 2 ATK ou moins jusqu''à la fin de ce tour, puis le détruit.', 'Elle n''emprunte jamais rien. Elle rend, mais brisé.', '/assets/card_art/demon/crimson-dominion.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Croc de Braise', 'Demon', 'Serviteur', 'Avant', 2, 3, 1, 'Commune', NULL, 'PACTE.', 'Chaque morsure lui coûte, à toi aussi.', '/assets/card_art/demon/embermaw.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Cultiste Zombifié', 'Mort-Vivant', 'Serviteur', 'Hybride', 2, 1, 2, 'Rare', NULL, 'Dernier Souffle : invoque un Cadavre Errant en rangée Avant.', 'Il a prié pour la mort éternelle. Il a été exaucé — à moitié.', '/assets/card_art/undead/zombified-cultist.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Cadavre Errant', 'Mort-Vivant', 'Serviteur', 'Hybride', 2, 1, 3, 'Commune', NULL, 'REMPART. CHAIR MORTE.', 'Personne ne se souvient de son nom. Lui non plus.', '/assets/card_art/undead/wandering-corpse.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Zombie Bouclier', 'Mort-Vivant', 'Serviteur', 'Avant', 2, 1, 5, 'Rare', NULL, 'REMPART. Blessure : réduit de 1 les dégâts reçus (minimum 1).', 'Les lames s''enfoncent dans la chair morte et s''y perdent.', '/assets/card_art/undead/shield-zombie.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Éclat de Putréfaction', 'Mort-Vivant', 'Incantation', NULL, 2, NULL, NULL, 'Rare', NULL, 'Détruit un enchantement ou rituel ennemi aléatoire, puis invoque un Rampant 1/1 en rangée Avant.', 'La corruption ne respecte pas la magie. Elle la digère.', '/assets/card_art/undead/shard-of-putrefaction.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Infecté Récent', 'Mort-Vivant', 'Serviteur', 'Avant', 2, 2, 2, 'Commune', NULL, 'Mort-rage : +1/+1 par ennemi infecté en jeu.', 'La morsure date d''hier. Il a encore ses yeux d''avant — mais plus rien derrière.', '/assets/card_art/undead/recently-infected.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Charognard Putride', 'Mort-Vivant', 'Serviteur', 'Avant', 2, 3, 1, 'Commune', NULL, 'Dernier Souffle : inflige Infection à un serviteur ennemi ciblé.', 'Même en tombant, il répand ce qui l''a tué.', '/assets/card_art/undead/putrid-scavenger.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Pestilent', 'Mort-Vivant', 'Serviteur', 'Hybride', 2, 1, 2, 'Rare', NULL, 'PESTIFÉRÉ : ses attaques infligent Infection en plus des dégâts.', 'Son souffle est une condamnation à retardement.', '/assets/card_art/undead/pestilent-one.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Souffle Nécrotique', 'Mort-Vivant', 'Incantation', NULL, 2, NULL, NULL, 'Commune', NULL, '2 dégâts à un serviteur ennemi ciblé.', 'Ce n''est pas du vent. C''est ce qui reste quand les poumons ne servent plus à rien.', '/assets/card_art/undead/necrotic-breath.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Zombie Mineur', 'Mort-Vivant', 'Serviteur', 'Avant', 2, 2, 2, 'Commune', NULL, 'HORDE : +1/+0 tant que tu contrôles 3 Morts-Vivants ou plus.', 'Il était enfant. C''était avant.', '/assets/card_art/undead/minor-zombie.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Étreinte Glaciale', 'Mort-Vivant', 'Incantation', NULL, 2, NULL, NULL, 'Commune', NULL, 'Gèle un serviteur ennemi ciblé un tour. (L''Infection continue.)', 'Le froid stoppe les gestes. Pas le mal qui ronge de l''intérieur.', '/assets/card_art/undead/icy-embrace.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Poigne du Cimetière', 'Mort-Vivant', 'Incantation', NULL, 2, NULL, NULL, 'Rare', NULL, 'Renvoie un serviteur ennemi de 3 HP ou moins dans la main de son propriétaire.', 'Les morts n''oublient pas ceux qui les ont enterrés.', '/assets/card_art/undead/grip-of-the-graveyard.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Don de Chair', 'Mort-Vivant', 'Incantation', NULL, 2, NULL, NULL, 'Rare', NULL, 'Sacrifice (un serviteur allié) : inflige 3 dégâts au héros ennemi.', 'Il a donné son corps. Il n''avait plus besoin de consentir.', '/assets/card_art/undead/gift-of-flesh.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Garde du Charnier', 'Mort-Vivant', 'Serviteur', 'Avant', 2, 1, 4, 'Rare', NULL, 'REMPART. Dernier Souffle : pioche 1 carte.', 'Il gardait les vivants. Il garde désormais ce qui reste.', '/assets/card_art/undead/charnel-guard.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Archer de Guet', 'Humain', 'Serviteur', 'Arriere', 2, 2, 1, 'Commune', NULL, 'Éveil : inflige 1 dégât à un serviteur ennemi aléatoire en rangée Avant.', 'Il ne rate pas. Il attend juste le bon moment.', '/assets/card_art/human/watchtower-archer.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Bénédiction de Guerre', 'Humain', 'Incantation', NULL, 2, NULL, NULL, 'Épique', NULL, 'Un serviteur Humain allié ciblé gagne +2/+2 et DISCIPLINE jusqu''à fin de tour.', 'Ce n''est pas de la magie. C''est la conviction que quelqu''un a mis dans ses mains.', '/assets/card_art/human/war-blessing.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Défenseur Juré', 'Humain', 'Serviteur', 'Avant', 2, 1, 4, 'Rare', NULL, 'REMPART. Blessure : les dégâts reçus sont réduits de 1 (minimum 1).', 'Il n''esquive pas. Il absorbe. Ce n''est pas pareil.', '/assets/card_art/human/sworn-defender.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Porteur de Bouclier', 'Humain', 'Serviteur', 'Avant', 2, 1, 4, 'Commune', NULL, 'REMPART.', 'Le bouclier a des marques de griffes. Il ne les compte plus.', '/assets/card_art/human/shield-bearer.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Fantassin Aguerri', 'Humain', 'Serviteur', 'Avant', 2, 2, 2, 'Commune', NULL, 'FORMATION : tant qu''un allié est adjacent, gagne +1/+1.', 'Seul, il tient. Ensemble, ils avancent.', '/assets/card_art/human/seasoned-footsoldier.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Sentinelle des Remparts', 'Humain', 'Serviteur', 'Avant', 2, 1, 5, 'Rare', NULL, 'REMPART. FORTIFICATION.', 'On a essayé de le faire reculer. On a essayé de le renvoyer. On a abandonné.', '/assets/card_art/human/rempart-sentinel.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Purification', 'Humain', 'Incantation', NULL, 2, NULL, NULL, 'Commune', NULL, 'Guérit l''Infection sur un serviteur allié ciblé.', 'Le mal recule. Pas loin. Mais pour l''instant, ça suffit.', '/assets/card_art/human/purification.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Lancier en Ligne', 'Humain', 'Serviteur', 'Avant', 2, 3, 1, 'Commune', NULL, 'FORMATION : tant qu''un allié est adjacent, gagne +1/+1.', 'La ligne tient ou la ligne tombe. Il n''y a pas d''entre-deux.', '/assets/card_art/human/line-lancer.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Frappe Coordonnée', 'Humain', 'Incantation', NULL, 2, NULL, NULL, 'Commune', NULL, 'Deux serviteurs Humains alliés attaquent immédiatement un serviteur ennemi ciblé.', 'Deux hommes, un seul endroit. L''ennemi n''a pas le temps de choisir lequel regarder.', '/assets/card_art/human/coordinated-strike.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Ordre d''Avancer', 'Humain', 'Incantation', NULL, 2, NULL, NULL, 'Rare', NULL, 'Tous les serviteurs Humains alliés en rangée Arrière gagnent +1 ATK de façon permanente.', 'L''ordre est arrivé. Il n''y avait pas de question à poser.', '/assets/card_art/human/advance-order.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Sommeil Qui Ronge', 'Abomination', 'Incantation', NULL, 2, NULL, NULL, 'Commune', NULL, 'Gèle un serviteur ennemi ciblé un tour ; à la fin du gel, il subit une mutation forcée : Dégénérescence.', 'Le froid ne le tue pas. Il le laisse simplement pourrir sur place.', '/assets/card_art/abomination/rotting-slumber.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Regard Détaché', 'Abomination', 'Serviteur', 'Arriere', 2, 1, 2, 'Commune', NULL, NULL, 'Il ne cligne jamais. Il n''a plus rien à protéger.', '/assets/card_art/abomination/detached-gaze.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Nœud de Chair', 'Abomination', 'Serviteur', 'Avant', 2, 2, 2, 'Commune', NULL, 'MUTATION.', 'Chaque coup reçu le noue un peu plus serré.', '/assets/card_art/abomination/flesh-knot.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Ce-Qui-Se-Partage', 'Abomination', 'Serviteur', 'Avant', 2, 3, 1, 'Commune', NULL, 'Dernier Souffle : le serviteur allié adjacent gagne +1/+1 permanent.', 'Il ne meurt pas vraiment. Il se répartit ailleurs.', '/assets/card_art/abomination/self-splitter.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Partage Forcé', 'Abomination', 'Incantation', NULL, 2, NULL, NULL, 'Rare', NULL, 'Sacrifice (un serviteur allié) : le serviteur allié adjacent absorbe ses stats restantes de façon permanente.', 'Rien ne se perd. Tout se recompose.', '/assets/card_art/abomination/forced-sharing.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Étau de Chair Neuve', 'Abomination', 'Incantation', NULL, 2, NULL, NULL, 'Rare', NULL, 'Renvoie un serviteur ennemi de 3 HP ou moins dans la main de son propriétaire.', 'Il revient. Mais ce n''est plus vraiment lui.', '/assets/card_art/abomination/fresh-flesh-vise.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Peau-Trop-Grande', 'Abomination', 'Serviteur', 'Arriere', 2, 1, 3, 'Commune', NULL, 'REMPART. INSTABLE.', 'Elle flotte autour de ce qu''elle contient, comme si elle attendait encore d''être remplie.', '/assets/card_art/abomination/ill-fitting-hide.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Fracture Vivante', 'Abomination', 'Incantation', NULL, 2, NULL, NULL, 'Rare', NULL, 'Détruit un enchantement ennemi aléatoire ; un serviteur Abomination allié aléatoire mute immédiatement.', 'La corruption ne respecte pas la magie. Elle la digère aussi.', '/assets/card_art/abomination/living-fracture.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Morsure de l''Air', 'Abomination', 'Incantation', NULL, 2, NULL, NULL, 'Commune', NULL, '2 dégâts à un serviteur ennemi ciblé ; s''il survit, il perd 1 ATK de façon permanente.', 'Ce qui ne tue pas ronge quand même.', '/assets/card_art/abomination/air-bite.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Communion Infernale', 'Demon', 'Rituel', NULL, 3, NULL, NULL, 'Rare', 4, 'Deuil : pioche 1 carte ; ton héros perd 1 HP.', 'Chaque mort te parle. Écouter a un coût, à chaque fois.', '/assets/card_art/demon/the-living-covenant.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Chevalier du Mur', 'Humain', 'Serviteur', 'Avant', 3, 2, 5, 'Rare', NULL, 'REMPART. CONTRE-ATTAQUE.', 'Il a juré de ne pas reculer. Il a tenu sa parole à un prix qu''il ne mentionne jamais.', '/assets/card_art/human/wall-knight.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Nuée de Tourments', 'Demon', 'Serviteur', 'Hybride', 3, 1, 2, 'Épique', NULL, 'TERREUR. Arrivée : inflige 1 dégât à tous les serviteurs ennemis en jeu.', 'Elle ne mord pas fort. Elle mord partout, et longtemps.', '/assets/card_art/demon/swarm-of-tourments.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Ordre de Tenir', 'Humain', 'Rituel', NULL, 3, NULL, NULL, 'Commune', 2, 'Éveil : tes serviteurs en rangée Avant ne peuvent pas être renvoyés en main ni déplacés par des effets ennemis.', 'L''ordre est simple. Les hommes, eux, sont compliqués. Mais ils obéissent.', '/assets/card_art/human/hold-order.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Autel des Damnés', 'Mort-Vivant', 'Enchantement', NULL, 3, NULL, NULL, 'Rare', NULL, 'Deuil : pioche 1 carte.', 'Chaque mort nourrit l''autel. L''autel, lui, ne se souvient d''aucun nom.', '/assets/card_art/undead/altar-of-the-damned.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Sceau du Répit', 'Demon', 'Enchantement', NULL, 3, NULL, NULL, 'Rare', NULL, 'Présence : quand un serviteur Démon allié meurt, ton héros regagne 1 HP.', 'Chaque perte laisse une trace. Celle-ci, au moins, te profite.', '/assets/card_art/demon/seal-of-respite.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Aura de Décrépitude', 'Mort-Vivant', 'Enchantement', NULL, 3, NULL, NULL, 'Rare', NULL, 'Résonance : ce serviteur Mort-Vivant attaquant gagne +1/+0 de façon permanente.', 'La décrépitude n''est pas une faiblesse. C''est une accumulation.', '/assets/card_art/undead/aura-of-decrepitude.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Buveur de Souffrance', 'Demon', 'Serviteur', 'Avant', 3, 2, 3, 'Rare', NULL, 'SANG NOIR.', 'Il ne ressent pas ta douleur. Il l''absorbe, littéralement.', '/assets/card_art/demon/pain-drinker.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Un-Devenu-Plusieurs', 'Abomination', 'Serviteur', 'Avant', 3, 1, 1, 'Commune', NULL, 'Arrivée : invoque 2 Amas Informes 1/2 en rangée Avant.', 'Il n''a jamais compris qu''il était censé rester seul.', '/assets/card_art/abomination/one-become-many.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Émissaire du Pacte', 'Demon', 'Serviteur', 'Hybride', 3, 2, 3, 'Rare', NULL, 'PACTE. Arrivée : pioche 1 carte.', 'Il apporte toujours plus qu''il ne semble offrir — dans les deux sens.', '/assets/card_art/demon/pact-emissary.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Mâcheur d''Os', 'Mort-Vivant', 'Serviteur', 'Avant', 3, 4, 2, 'Commune', NULL, 'ASSAUT. Ralliement : inflige 1 dégât splash aux serviteurs adjacents à la cible.', 'Le craquement des os est le seul son qu''il comprend encore.', '/assets/card_art/undead/bone-chewer.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Architecte du Pacte', 'Demon', 'Serviteur', 'Arriere', 3, 2, 3, 'Épique', NULL, 'PACTE. Ralliement : invoque une Larve Infernale 2/1 en rangée Avant.', 'Chaque contrat qu''il signe en engendre un autre, sans fin.', '/assets/card_art/demon/pact-architect.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Marque du Pacte', 'Demon', 'Incantation', NULL, 3, NULL, NULL, 'Rare', NULL, 'Un serviteur Démon allié ciblé gagne PACTE et RANG INFERNAL jusqu''à fin de tour.', 'La marque ne s''efface pas. Elle attend juste son heure.', '/assets/card_art/demon/mark-of-the-pact.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Nuée d''Insectes Cadavériques', 'Mort-Vivant', 'Serviteur', 'Hybride', 3, 1, 2, 'Épique', NULL, 'Arrivée : inflige 1 dégât à tous les serviteurs ennemis en jeu.', 'Là où elle passe, rien ne guérit vraiment.', '/assets/card_art/undead/cadaverous-insect-swarm.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Sceau de Préservation', 'Demon', 'Enchantement', NULL, 3, NULL, NULL, 'Rare', NULL, 'Présence : réduit de 1 (minimum 0) les dégâts que tes propres cartes infligent à ton héros, à chaque occurrence.', 'Une clause discrète, glissée dans les petits caractères — en ta faveur, pour une fois.', '/assets/card_art/demon/keeper-of-the-black-throne.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Sursaut Final', 'Abomination', 'Incantation', NULL, 3, NULL, NULL, 'Épique', NULL, 'Ramène immédiatement en jeu le dernier serviteur Abomination allié mort.', 'Une dernière contraction. Ça suffit parfois à repartir.', '/assets/card_art/abomination/final-spasm.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Éclaireur Infiltré', 'Humain', 'Serviteur', 'Avant', 3, 3, 2, 'Rare', NULL, 'Arrivée : tous les serviteurs ennemis en rangée Arrière ne peuvent pas être ciblés par des sorts ennemis ce tour.', 'Il est allé voir. Il est revenu. Pas tout le monde n''en peut dire autant.', '/assets/card_art/human/infiltrator-scout.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Mort-Vivant Enchaîné', 'Mort-Vivant', 'Serviteur', 'Avant', 3, 3, 3, 'Commune', NULL, 'HORDE : +1/+0 tant que tu contrôles 3 Morts-Vivants ou plus.', 'Les chaînes ne le retiennent plus. Elles font partie de lui.', '/assets/card_art/undead/chained-undead.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Communion avec les Morts', 'Mort-Vivant', 'Rituel', NULL, 3, NULL, NULL, 'Rare', 4, 'Deuil : pioche 1 carte par Mort-Vivant allié mort ce match (max 4).', 'Chaque mort laisse quelque chose derrière lui. Il suffit de savoir écouter.', '/assets/card_art/undead/communion-with-the-death.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Cri des Damnés', 'Mort-Vivant', 'Incantation', NULL, 3, NULL, NULL, 'Rare', NULL, 'Mort-Vivants alliés +1/+0 ce tour. Si 5 ou plus en jeu : +2/+0 à la place.', 'Plus ils sont nombreux à hurler, moins le cri ressemble à quelque chose d''humain.', '/assets/card_art/undead/cry-of-the-damned.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Écho des Chutes', 'Abomination', 'Rituel', NULL, 3, NULL, NULL, 'Rare', 4, 'Dévoration : pioche 1 carte (une seule fois par tour).', 'Chaque mort, où qu''elle soit, nourrit le cercle.', '/assets/card_art/abomination/echo-of-the-fallen.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Soldat de la Foi', 'Humain', 'Serviteur', 'Avant', 3, 2, 3, 'Rare', NULL, 'ÉGIDE. Dernier Souffle : invoque un Milicien du Bourg 2/1 en rangée Avant.', 'Il croyait en quelque chose. Ce quelque chose l''a protégé — une fois.', '/assets/card_art/human/faith-soldier.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Armure Fondue', 'Abomination', 'Serviteur', 'Avant', 3, 4, 3, 'Rare', NULL, 'MUTATION. INSTABLE.', 'Le métal a fusionné avec ce qu''il était censé protéger. Impossible de dire où l''un finit et l''autre commence.', '/assets/card_art/abomination/molten-armor.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Lame-Jurée', 'Humain', 'Serviteur', 'Avant', 3, 4, 2, 'Rare', NULL, 'DISCIPLINE. Exécution : gagne +1/+1 de façon permanente.', 'Elle a juré sur sa lame. La lame, elle, a juré de le mériter.', '/assets/card_art/human/sworn-blade.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Archer d''Élite', 'Humain', 'Serviteur', 'Arriere', 3, 3, 2, 'Rare', NULL, 'INFILTRATION : peut cibler n''importe quel serviteur ennemi (Avant ou Arrière).', 'La rangée Avant n''est pas un obstacle. C''est un couloir.', '/assets/card_art/human/elite-archer.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Jugement Divin', 'Humain', 'Incantation', NULL, 3, NULL, NULL, 'Rare', NULL, 'Détruit un serviteur ennemi ayant 2 ATK ou moins.', 'Le verdict est rendu avant même que l''accusé comprenne qu''il était jugé.', '/assets/card_art/human/divine-judgment.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Formation Défensive', 'Humain', 'Incantation', NULL, 3, NULL, NULL, 'Épique', NULL, 'Tous tes serviteurs en rangée Avant gagnent REMPART et +0/+2 jusqu''à fin du tour adverse.', 'Ils se serrent. La ligne devient un mur. Le mur ne bouge pas.', '/assets/card_art/human/defensive-fomation.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Marche Forcée', 'Humain', 'Rituel', NULL, 3, NULL, NULL, 'Rare', 2, 'Éveil : invoque un Éclaireur Rapide 1/1 en rangée Avant gratuitement.', 'Pas de repos. Pas d''arrêt. La ligne avance parce que s''arrêter, c''est mourir.', '/assets/card_art/human/forced-march.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Semeur de Nœuds', 'Abomination', 'Serviteur', 'Arriere', 3, 2, 3, 'Épique', NULL, 'FUSION. Ralliement : invoque un Amas Informe 1/2 en rangée Avant.', 'Il ne construit rien. Il fait pousser.', '/assets/card_art/abomination/knot-sower.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Vétéran des Marches', 'Humain', 'Serviteur', 'Avant', 3, 2, 4, 'Commune', NULL, 'Blessure : gagne +1/+0 de façon permanente.', 'Chaque cicatrice lui a appris quelque chose. Il en a beaucoup appris.', '/assets/card_art/human/march-veteran.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Pacte de Résistance', 'Humain', 'Enchantement', NULL, 3, NULL, NULL, 'Rare', NULL, 'Présence : les serviteurs Humains alliés reçoivent 1 dégât de moins de toute source (minimum 1).', 'Ils ont signé ensemble. Aucun d''eux ne s''en souvient exactement. Tous s''en souviennent suffisamment.', '/assets/card_art/human/resistance-pact.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Contre-Offensive', 'Humain', 'Incantation', NULL, 3, NULL, NULL, 'Rare', NULL, 'Exécution ce tour : chaque serviteur Humain allié qui tue un ennemi peut attaquer à nouveau immédiatement.', 'La victoire s''enchaîne quand on ne lui laisse pas le temps de s''arrêter.', '/assets/card_art/human/counter-offensive.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Bouche-Mère', 'Abomination', 'Serviteur', 'Avant', 3, 3, 3, 'Rare', NULL, 'ASSIMILATION.', 'Elle ne distingue pas allié et ennemi. Seulement mort et pas-encore-mort.', '/assets/card_art/abomination/mother-maw.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Lignée des Braves', 'Humain', 'Enchantement', NULL, 3, NULL, NULL, 'Rare', NULL, 'Deuil : quand un Humain allié meurt, pioche 1 carte. (Une seule fois par tour.)', 'Chaque nom gravé est aussi une leçon. Il suffit de savoir la lire.', '/assets/card_art/human/lineage-of-the-brave.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Guérisseur de Camp', 'Humain', 'Serviteur', 'Arriere', 3, 0, 3, 'Commune', NULL, 'Éveil : restaure 1 HP à un serviteur Humain allié aléatoire.', 'Il n''a jamais tenu d''épée. Ses mains ont pourtant sauvé plus de vies que n''importe quelle lame.', '/assets/card_art/human/camp-healer.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Frère d''Armes', 'Humain', 'Serviteur', 'Avant', 3, 3, 2, 'Commune', NULL, 'Assaut : le serviteur allié adjacent gagne +0/+1.', 'Il ne combat pas pour la victoire. Il combat pour que l''homme à sa gauche rentre chez lui.', '/assets/card_art/human/brother-in-arms.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Porte-Étendard', 'Humain', 'Serviteur', 'Arriere', 3, 1, 4, 'Épique', NULL, 'Arrivée : invoque un Éclaireur Rapide 1/1 en rangée Avant pour chaque Humain déjà en jeu (max 3).', 'L''étendard ne se rend pas. Tant qu''il tient, les autres tiennent aussi.', '/assets/card_art/human/standard-bearer.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Volée de Flèches', 'Humain', 'Incantation', NULL, 3, NULL, NULL, 'Commune', NULL, 'Inflige 1 dégât à tous les serviteurs ennemis en rangée Avant. Si 4 ou plus en rangée Avant : 2 dégâts à la place.', 'Plus ils sont nombreux, plus ça fait de cibles.', '/assets/card_art/human/arrow-volley.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Pluie Qui Change', 'Abomination', 'Incantation', NULL, 3, NULL, NULL, 'Commune', NULL, '1 dégât à tous les serviteurs ennemis en rangée Avant ; les survivants ont -1 ATK jusqu''à la fin du tour.', 'L''air lui-même devient hostile en son sillage.', '/assets/card_art/abomination/mutating-rain.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Ombre à Plusieurs Corps', 'Abomination', 'Serviteur', 'Avant', 3, 4, 2, 'Épique', NULL, 'AILES NOIRES. FUSION.', 'Elle n''a jamais eu qu''un seul visage à la fois. Elle en emprunte un nouveau à chaque cible.', '/assets/card_art/abomination/many-bodied-shadow.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Vague de Corruption', 'Demon', 'Incantation', NULL, 3, NULL, NULL, 'Commune', NULL, 'Inflige Corruption à tous les serviteurs ennemis en rangée Avant.', 'Rien ne pourrit d''un coup. Tout pourrit, éventuellement.', '/assets/card_art/demon/wave-of-corruption.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Sergent de Troupe', 'Humain', 'Serviteur', 'Hybride', 3, 2, 3, 'Commune', NULL, 'Arrivée : les serviteurs Humains alliés en rangée Avant gagnent +0/+1 jusqu''à fin de tour.', 'Sa voix porte plus loin que le bruit du combat. C''est pour ça qu''il est encore en vie.', '/assets/card_art/human/troop-sergeant.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Inquisiteur de Fer', 'Humain', 'Serviteur', 'Hybride', 3, 3, 2, 'Rare', NULL, 'Arrivée : silence un serviteur ennemi ciblé jusqu''à fin du prochain tour adverse.', 'Il ne cherche pas la vérité. Il coupe ce qui parle à la place d''elle.', '/assets/card_art/human/iron-inquisitor.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Ultime Sacrifice', 'Demon', 'Incantation', NULL, 3, NULL, NULL, 'Épique', NULL, 'Sacrifice (jusqu''à 3 serviteurs alliés) : pioche 1 carte par sacrifié ; ton héros perd 1 HP par sacrifié.', 'Ils ne meurent pas pour rien. Ils meurent pour que tu continues — de justesse.', '/assets/card_art/demon/ultimate-sacrifice.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Assassin des Ombres Rouges', 'Demon', 'Serviteur', 'Avant', 3, 4, 2, 'Épique', NULL, 'INFILTRATION. PACTE.', 'Il ne frappe jamais ce qu''on protège. Il frappe ce qu''on croyait à l''abri.', '/assets/card_art/demon/crimson-shadow-assassin.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Dernier Soupir', 'Mort-Vivant', 'Incantation', NULL, 3, NULL, NULL, 'Épique', NULL, 'Carnage : pioche 1 carte par Mort-Vivant allié mort ce tour (max 3).', 'Leurs voix ne portent plus. Mais leurs secrets, si.', '/assets/card_art/undead/last-breath.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Soldat Réanimé', 'Mort-Vivant', 'Serviteur', 'Avant', 3, 4, 3, 'Rare', NULL, 'REVENANT : la première fois qu''il devrait mourir, se relève avec 1 HP.', 'La mort lui a appris ce que la guerre ne lui avait pas enseigné : la patience.', '/assets/card_art/undead/reanimated-soldier.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Possédé Hurlant', 'Mort-Vivant', 'Serviteur', 'Avant', 3, 5, 1, 'Rare', NULL, 'ASSAUT. VENIN MORTEL. Dernier Souffle : retiré du jeu (ne va pas au cimetière).', 'Même les morts refusent de le reprendre.', '/assets/card_art/undead/screaming-possessed.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Autel des Sacrifices', 'Demon', 'Enchantement', NULL, 3, NULL, NULL, 'Rare', NULL, 'Deuil : ton héros perd 1 HP ; pioche 1 carte.', 'L''autel ne demande jamais deux fois. Il attend, c''est tout.', '/assets/card_art/demon/altar-of-sacrifice.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Possédé Écarlate', 'Demon', 'Serviteur', 'Avant', 3, 5, 1, 'Rare', NULL, 'ASSAUT. TERREUR.', 'Il ne réfléchit plus. Quelque chose réfléchit à sa place, et ça va vite.', '/assets/card_art/demon/crimson-possessed.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Horde Mineure', 'Mort-Vivant', 'Serviteur', 'Hybride', 3, 1, 1, 'Commune', NULL, 'Arrivée : invoque 2 Rampants 1/1 en rangée Avant.', 'Un seul ne fait pas peur. Mais il n''est jamais seul.', '/assets/card_art/undead/minor-horde.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Halo Qui Encourage le Changement', 'Abomination', 'Enchantement', NULL, 3, NULL, NULL, 'Rare', NULL, 'Résonance : le serviteur qui vient de muter gagne +1/+0 supplémentaire de façon permanente.', 'Chaque changement en appelle un autre, plus franc.', '/assets/card_art/abomination/change-encouraging-halo.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Hurleur Nécrotique', 'Mort-Vivant', 'Serviteur', 'Hybride', 3, 3, 2, 'Rare', NULL, 'Arrivée : serviteurs Mort-Vivants alliés en rangée Avant +1/+0 jusqu''à fin de tour.', 'Son cri ne terrorise plus. Il réveille.', '/assets/card_art/undead/necrotic-howler.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Vase Brisé, Encore Plein', 'Abomination', 'Serviteur', 'Avant', 3, 5, 1, 'Rare', NULL, 'ASSAUT. VENIN MORTEL. Dernier Souffle : se reforme en Amas Informe 2/2 sous ton contrôle (ne va pas au cimetière).', 'Il ne meurt jamais tout à fait. Il se réarrange.', '/assets/card_art/abomination/shattered-vessel.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Aura de Corruption', 'Demon', 'Enchantement', NULL, 3, NULL, NULL, 'Rare', NULL, 'Résonance : ce Démon attaquant inflige Corruption supplémentaire à sa cible.', 'La corruption ne recule jamais. Elle s''accumule, discrètement.', '/assets/card_art/demon/aura-of-corruption.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Harpie Carmine', 'Demon', 'Serviteur', 'Avant', 3, 4, 2, 'Commune', NULL, 'TERREUR.', 'Son cri ne blesse pas. Il paralyse.', '/assets/card_art/demon/carmine-harpy.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Emprunt de Peau', 'Abomination', 'Serviteur', 'Hybride', 3, 2, 3, 'Commune', NULL, 'CHAIR ADAPTATIVE.', 'Elle n''a rien à elle. Elle prend ce qui traîne à côté.', '/assets/card_art/abomination/borrowed-skin.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Sentinelle du Gouffre', 'Demon', 'Serviteur', 'Arriere', 3, 1, 4, 'Commune', NULL, 'REMPART. Blessure : ton héros perd 1 HP ; ce serviteur regagne 1 HP.', 'Elle boit la douleur des autres. La tienne fera l''affaire.', '/assets/card_art/demon/abyssal-sentinel.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Poussière Qui Change', 'Abomination', 'Serviteur', 'Hybride', 3, 1, 2, 'Épique', NULL, 'VIRULENT. Arrivée : inflige 1 dégât à tous les serviteurs ennemis en jeu.', 'Là où elle se dépose, quelque chose commence toujours à changer.', '/assets/card_art/abomination/shifting-dust.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Appétit Ciblé', 'Abomination', 'Incantation', NULL, 3, NULL, NULL, 'Rare', NULL, 'Détruit un serviteur ennemi ayant 2 HP ou moins ; un serviteur Abomination allié aléatoire gagne +1/+1 permanent.', 'Rien ne se jette. Tout se digère.', '/assets/card_art/abomination/targeted-appetite.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Chant Qui Déforme', 'Abomination', 'Incantation', NULL, 3, NULL, NULL, 'Rare', NULL, 'Abominations alliées +1/+0 ce tour. Si 5 ou plus en jeu : elles mutent aussi immédiatement.', 'Un seul chant, mille chairs qui répondent en changeant de forme.', '/assets/card_art/abomination/song-of-distortion.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Brouillard Pestilentiel', 'Mort-Vivant', 'Enchantement', NULL, 3, NULL, NULL, 'Rare', NULL, 'Présence : à chaque début du tour adverse, les serviteurs ennemis infectés perdent 1 HP supplémentaire.', 'On ne le voit pas. On ne le sent même plus, après un moment.', '/assets/card_art/undead/pestilential-fog.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Autel Qui Ne Reconnaît Rien', 'Abomination', 'Enchantement', NULL, 3, NULL, NULL, 'Rare', NULL, 'Deuil : un serviteur Abomination allié aléatoire mute.', 'Chaque mort nourrit l''autel. L''autel, lui, ne rend jamais la même forme deux fois.', '/assets/card_art/abomination/unrecognizing-altar.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Vague de Putréfaction', 'Mort-Vivant', 'Incantation', NULL, 3, NULL, NULL, 'Commune', NULL, '1 dégât à tous les serviteurs ennemis en rangée Avant.', 'La peste ne choisit pas. Elle couvre.', '/assets/card_art/undead/wave-of-putrefaction.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Bourreau Mineur', 'Demon', 'Serviteur', 'Avant', 3, 3, 3, 'Commune', NULL, 'Exécution : ton héros perd 1 HP ; ce serviteur gagne +1/+1 de façon permanente.', 'Chaque exécution le nourrit — et te vide un peu.', '/assets/card_art/demon/hellbound-executioner.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Assassin Décharné', 'Mort-Vivant', 'Serviteur', 'Avant', 3, 4, 2, 'Épique', NULL, 'INFILTRATION. Ne peut pas être ciblé par les sorts ennemis jusqu''à sa première attaque.', 'On ne le voit pas venir. On ne le voit que partir.', '/assets/card_art/undead/gaunt-assassin.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Suppôt du Répit', 'Demon', 'Serviteur', 'Arriere', 3, 2, 3, 'Rare', NULL, 'Blessure : ton héros regagne 1 HP.', 'Chaque coup qu''il encaisse repart, transformé, vers celui qu''il protège.', '/assets/card_art/demon/harbinger-of-respite.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Servant Décharné', 'Mort-Vivant', 'Serviteur', 'Arriere', 3, 2, 4, 'Commune', NULL, 'Ralliement : tes serviteurs en rangée Avant ont +0/+1 HP.', 'Il ne commande pas. Il pousse. Et ça suffit.', '/assets/card_art/undead/gaunt-servant.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Second Regard', 'Abomination', 'Serviteur', 'Arriere', 3, 2, 3, 'Rare', NULL, 'CHAIR ADAPTATIVE. Arrivée : pioche 1 carte.', 'Il voit ce que les autres pourraient devenir, avant qu''ils ne le sachent eux-mêmes.', '/assets/card_art/abomination/second-gaze.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Voix-Sous-la-Peau', 'Abomination', 'Serviteur', 'Arriere', 3, 2, 3, 'Rare', NULL, 'Arrivée : le serviteur allié adjacent gagne CHAIR ADAPTATIVE de façon permanente.', 'Elle ne donne pas d''ordres. Elle se contente de murmurer, et la chair voisine écoute.', '/assets/card_art/abomination/voice-beneath-the-skin.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Vapeur Qui S''Accroche', 'Abomination', 'Enchantement', NULL, 3, NULL, NULL, 'Rare', NULL, 'Éveil : inflige 1 dégât à un serviteur ennemi aléatoire.', 'On ne la voit pas. On sent juste que quelque chose continue de ronger.', '/assets/card_art/abomination/clinging-vapor.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Le Poids-Qui-Marche', 'Abomination', 'Serviteur', 'Avant', 3, 2, 4, 'Commune', NULL, 'MUTATION. ASSIMILATION.', 'On ne sait pas ce qu''il porte. Lui non plus.', '/assets/card_art/abomination/walking-weight.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Architecte de la Horde', 'Mort-Vivant', 'Serviteur', 'Arriere', 3, 2, 3, 'Épique', NULL, 'Appel : invoque un Rampant 1/1 en rangée Avant.', 'Il ne construit pas d''armée. Il la sécrète.', '/assets/card_art/undead/horde-architect.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Chevalier Déchu', 'Demon', 'Serviteur', 'Avant', 3, 4, 3, 'Rare', NULL, 'PACTE.', 'Son armure était sacrée, autrefois. Elle a changé de camp avec lui.', '/assets/card_art/demon/fallen-hellknight.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Absolution Écarlate', 'Demon', 'Incantation', NULL, 3, NULL, NULL, 'Rare', NULL, 'Les dégâts que tes cartes infligeraient à ton héros ce tour sont annulés.', 'Pour une fois, le contrat se tait.', '/assets/card_art/demon/eternal-ceremony.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Morsure Infectieuse', 'Mort-Vivant', 'Incantation', NULL, 3, NULL, NULL, 'Rare', NULL, 'Transforme un serviteur ennemi non-Légendaire en Zombie 1/1 sous ton contrôle.', 'Une seule morsure suffit. Le reste, c''est une question de temps.', '/assets/card_art/undead/infectious-bite.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Visage-Encore-Flou', 'Abomination', 'Serviteur', 'Avant', 3, 3, 3, 'Commune', NULL, 'FUSION.', 'Il essaie plusieurs expressions. Aucune ne lui va tout à fait.', '/assets/card_art/abomination/blurred-visage.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Hurlement Écarlate', 'Demon', 'Incantation', NULL, 3, NULL, NULL, 'Rare', NULL, 'Démons alliés +1/+0 ce tour. Ton héros perd 2 HP. Si 5 ou plus en jeu : +2/+0 à la place.', 'Plus ils sont nombreux à hurler, plus le prix grimpe — pour toi.', '/assets/card_art/demon/crimson-wail.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Séducteur Écarlate', 'Demon', 'Serviteur', 'Arriere', 3, 2, 3, 'Rare', NULL, 'Ralliement : la cible perd 1 ATK de façon permanente (Corruption).', 'Il ne promet rien. Il se contente de prendre, doucement.', '/assets/card_art/demon/crimson-tempter.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Faim Sans Fond', 'Abomination', 'Serviteur', 'Hybride', 4, 4, 4, 'Épique', NULL, 'MOISSON. ASSIMILATION.', 'Elle ne prend pas la vie. Elle l''intègre.', '/assets/card_art/abomination/bottomless-hunger.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Nécromancien Putride', 'Mort-Vivant', 'Serviteur', 'Arriere', 4, 2, 4, 'Épique', NULL, 'Arrivée : ressuscite le dernier Mort-Vivant allié mort avec 1 HP en rangée Avant.', NULL, '/assets/card_art/undead/putrid-necromancer.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Rituel d''Exhumation', 'Mort-Vivant', 'Rituel', NULL, 4, NULL, NULL, 'Rare', 3, 'Éveil : si ton cimetière contient un Mort-Vivant, ramène-le en main.', 'On ne l''enterre pas. On l''entrepose.', '/assets/card_art/undead/ritual-of-the-exhumation.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Repaire Qui Digère la Magie', 'Abomination', 'Enchantement', NULL, 4, NULL, NULL, 'Épique', NULL, 'Présence : les sorts alliés coûtent 1 de moins (min 1).', 'Dans ses murs, tout se transforme un peu plus vite, même les sorts.', '/assets/card_art/abomination/magic-digesting-lair.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Rituel du Lien Funeste', 'Mort-Vivant', 'Rituel', NULL, 4, NULL, NULL, 'Épique', 3, 'Deuil : inflige 2 dégâts au héros ennemi.', 'Chaque allié qui tombe tire un fil. L''ennemi finit par sentir la traction.', '/assets/card_art/undead/ritual-of-the-dommed-bond.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Capitaine de Milice', 'Humain', 'Serviteur', 'Hybride', 4, 3, 3, 'Rare', NULL, 'COMMANDEMENT. Arrivée : invoque un Milicien du Bourg 2/1 en rangée Avant.', 'Il n''avait pas prévu de commander. Mais quelqu''un devait le faire.', '/assets/card_art/human/militia-captain.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Esprit Vorace', 'Mort-Vivant', 'Serviteur', 'Hybride', 4, 4, 4, 'Épique', NULL, 'MOISSON. Arrivée : vole 2 HP au héros ennemi.', 'Il ne prend pas ta vie. Il la déplace — dans les mauvaises mains.', '/assets/card_art/undead/voracious-spirit.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Banshee Zombie', 'Mort-Vivant', 'Serviteur', 'Hybride', 4, 2, 5, 'Rare', NULL, 'Arrivée : silence un serviteur ennemi ciblé jusqu''à fin du prochain tour adverse.', 'Elle hurle sans voix. Ceux qu''elle regarde oublient comment parler.', '/assets/card_art/undead/banshee.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Rongeur de Chair', 'Mort-Vivant', 'Serviteur', 'Avant', 4, 5, 3, 'Rare', NULL, 'Exécution : peut attaquer à nouveau une fois par tour.', 'Il ne s''arrête pas quand la proie tombe. Il s''arrête quand il ne reste plus rien.', '/assets/card_art/undead/flesh-gnawer.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Épidémie', 'Mort-Vivant', 'Rituel', NULL, 4, NULL, NULL, 'Épique', 1, 'Serviteurs ennemis -2/-2.', 'Elle ne tue pas. Elle prépare.', '/assets/card_art/undead/epidemic.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Cavalier Zombie', 'Mort-Vivant', 'Serviteur', 'Avant', 4, 4, 3, 'Rare', NULL, 'ASSAUT. Arrivée : attaque immédiatement le serviteur ennemi le plus faible en HP.', 'Le cheval est mort avant lui. Ni l''un ni l''autre ne s''en est rendu compte.', '/assets/card_art/undead/deadrider.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Main-Qui-Choisit', 'Abomination', 'Serviteur', 'Avant', 4, 5, 3, 'Rare', NULL, 'Exécution : déclenche immédiatement une mutation.', 'Chaque mise à mort la change un peu plus.', '/assets/card_art/abomination/culling-hand.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Le Premier Écart', 'Abomination', 'Serviteur', 'Hybride', 4, 3, 3, 'Épique', NULL, 'Arrivée : tous tes serviteurs Abomination alliés mutent immédiatement.', 'Tout a commencé par une simple erreur de forme. Rien ne s''est arrêté depuis.', '/assets/card_art/abomination/first-deviation.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Berserker Infecté', 'Mort-Vivant', 'Serviteur', 'Avant', 4, 5, 4, 'Épique', NULL, 'FRÉNÉSIE. REVENANT. Mort-rage : +3/+0.', 'La fièvre l''a tué. Ce qui reste est plus rapide.', '/assets/card_art/undead/infected-berserker.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Pacte Sanglant', 'Mort-Vivant', 'Rituel', NULL, 4, NULL, NULL, 'Épique', 3, 'Sacrifice (un serviteur allié à 2 HP ou moins) : invoque un Mort-Vivant 2/2.', 'Chaque tour, le cercle redemande son dû — et chaque fois, il redonne quelque chose en retour.', '/assets/card_art/undead/blood-pact.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Prêtre de Guerre', 'Humain', 'Serviteur', 'Arriere', 4, 1, 4, 'Rare', NULL, 'Éveil : restaure 2 HP à un serviteur Humain allié aléatoire. Dernier Souffle : invoque un Éclaireur Rapide 1/1.', 'Il priait pour les vivants. À la fin, il a prié pour quelque chose de plus modeste : du temps.', '/assets/card_art/human/war-priest.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Fosse Commune', 'Mort-Vivant', 'Enchantement', NULL, 4, NULL, NULL, 'Rare', NULL, 'Appel : si 3 Mort-Vivants alliés ou plus sont en jeu, invoque un Rampant 1/1. (Une seule fois par tour.)', 'Plus elle se remplit, plus elle déborde.', '/assets/card_art/undead/mass-grave.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Hymne de Guerre', 'Humain', 'Rituel', NULL, 4, NULL, NULL, 'Rare', 3, 'Ralliement : le serviteur Humain invoqué gagne +1/+1.', 'Le chant ne les rend pas invincibles. Il leur rappelle qu''ils ne sont pas seuls.', '/assets/card_art/human/war-hymn.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Sanctuaire Nécrotique', 'Mort-Vivant', 'Enchantement', NULL, 4, NULL, NULL, 'Épique', NULL, 'Présence : les sorts alliés coûtent 1 de moins (min 1).', 'Dans ses murs, la magie de mort coule comme de l''eau froide — naturellement.', '/assets/card_art/undead/necrotic-sanctuary.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Le Patient Zéro', 'Mort-Vivant', 'Serviteur', 'Hybride', 4, 3, 3, 'Épique', NULL, 'Arrivée : inflige Infection à tous les serviteurs ennemis en jeu.', 'On n''a jamais su d''où il venait. On a fini par ne plus chercher.', '/assets/card_art/undead/patient-zero.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Fureur Sans Forme Fixe', 'Abomination', 'Serviteur', 'Avant', 4, 5, 4, 'Épique', NULL, 'FRÉNÉSIE. MUTATION.', 'Plus il frappe, moins il ressemble à ce qu''il était en arrivant.', '/assets/card_art/abomination/formless-fury.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Masse-Qui-Ne-Cesse', 'Abomination', 'Serviteur', 'Avant', 4, 4, 5, 'Rare', NULL, 'MUTATION. REMPART.', 'Elle a arrêté de compter les formes qu''elle a portées.', '/assets/card_art/abomination/ceaseless-mass.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Mur de Lances', 'Humain', 'Serviteur', 'Avant', 4, 1, 6, 'Épique', NULL, 'REMPART. FORMATION. Carnage : inflige 1 dégât à tous les serviteurs ennemis en rangée Avant.', 'Ils ne bougent pas. La ligne tient. Les lances, elles, trouvent toujours quelque chose à traverser.', '/assets/card_art/human/spear-wall.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Bouclier de la Foi', 'Humain', 'Enchantement', NULL, 4, NULL, NULL, 'Épique', NULL, 'Présence : tes serviteurs alliés reçoivent 2 dégâts de moins de toute source (minimum 1).', 'La foi ne comprend pas la magie. Elle n''a pas besoin de la comprendre pour la freiner.', '/assets/card_art/human/absolute-grace.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Massacre Sacré', 'Humain', 'Incantation', NULL, 4, NULL, NULL, 'Épique', NULL, 'Inflige 3 dégâts à tous les serviteurs Mort-Vivants ennemis en jeu.', 'La lumière ne guérit pas les morts. Elle les brûle. C''est mieux.', '/assets/card_art/human/sacred-massacre.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Stratège Royal', 'Humain', 'Serviteur', 'Arriere', 4, 2, 4, 'Épique', NULL, 'Présence : un allié invoqué dans une rangée pleine est placé dans l''autre rangée au lieu d''échouer.', 'Il ne voit pas un champ de bataille. Il voit un problème à résoudre.', '/assets/card_art/human/royal-strategist.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Le Sculpteur Sans Mains', 'Abomination', 'Serviteur', 'Arriere', 4, 2, 4, 'Épique', NULL, 'Arrivée : un serviteur allié ciblé gagne MUTATION de façon permanente.', '"La forme n''est qu''une suggestion. Je préfère négocier."', '/assets/card_art/abomination/handless-sculptor.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Émissaire de la Peste', 'Mort-Vivant', 'Serviteur', 'Hybride', 4, 3, 4, 'Rare', NULL, 'PESTIFÉRÉ : ses attaques infligent Infection en plus des dégâts.', 'Il ne vient pas combattre. Il vient annoncer.', '/assets/card_art/undead/plague-emissary.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Citadelle des Hommes', 'Humain', 'Enchantement', NULL, 4, NULL, NULL, 'Rare', NULL, 'Présence : tes serviteurs en rangée Avant ont +0/+1 HP de façon permanente.', 'Ces murs n''ont pas été construits pour durer. Ils ont duré quand même.', '/assets/card_art/human/citadel-of-men.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Champion du Peuple', 'Humain', 'Serviteur', 'Avant', 4, 5, 4, 'Épique', NULL, 'Exécution : soigne le héros allié de 2 HP.', 'Il se bat pour des gens qu''il ne connaît pas. C''est pour ça qu''il gagne.', '/assets/card_art/human/champion-of-the-people.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Appel aux Armes', 'Humain', 'Incantation', NULL, 4, NULL, NULL, 'Rare', NULL, 'Invoque 2 Miliciens du Bourg 2/1 en rangée Avant. Si ta rangée Avant est vide : invoque 3 Miliciens du Bourg à la place.', 'Quand la ligne est vide, ceux qui restent n''ont plus à réfléchir. Ils avancent.', '/assets/card_art/human/call-to-arms.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Serment du Sang', 'Humain', 'Rituel', NULL, 4, NULL, NULL, 'Rare', 3, 'Deuil : quand un Humain allié meurt, le serviteur allié adjacent gagne +1/+1.', 'Le serment survit à celui qui l''a fait. C''est l''idée.', '/assets/card_art/human/blood-oath.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Doigt-Dans-les-Nerfs', 'Abomination', 'Serviteur', 'Arriere', 4, 2, 5, 'Rare', NULL, 'Arrivée : réduit l''ATK d''un serviteur ennemi ciblé de 1 jusqu''à la fin du prochain tour adverse.', 'Un seul contact suffit à dérégler ce qui reste de coordination.', '/assets/card_art/abomination/nerve-touch.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Le Corrupteur', 'Demon', 'Serviteur', 'Hybride', 4, 3, 3, 'Épique', NULL, 'Arrivée : inflige Corruption à tous les serviteurs ennemis en jeu.', 'Il n''a pas besoin de convaincre. Il lui suffit de rester assez longtemps.', '/assets/card_art/demon/the-corrupter.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Suceur d''Âmes', 'Demon', 'Serviteur', 'Hybride', 4, 4, 4, 'Épique', NULL, 'MOISSON. Arrivée : ton héros perd 2 HP ; vole 4 HP au héros ennemi.', 'Il prélève des deux côtés. C''est ce qui rend le marché intéressant, pour lui.', '/assets/card_art/demon/soul-devourer.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Berserker du Pacte', 'Demon', 'Serviteur', 'Avant', 4, 5, 4, 'Épique', NULL, 'FRÉNÉSIE. PACTE.', 'Chaque contrat qu''il signe le rend plus rapide, et toi plus vulnérable.', '/assets/card_art/demon/pact-berserker.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Nid Débordant', 'Abomination', 'Enchantement', NULL, 4, NULL, NULL, 'Rare', NULL, 'Appel : si 3 Abominations alliées ou plus sont en jeu, invoque un Amas Informe 1/2 (une seule fois par tour).', 'Plus il se remplit, plus il en sort.', '/assets/card_art/abomination/overflowing-nest.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Accord de la Chair Neuve', 'Abomination', 'Rituel', NULL, 4, NULL, NULL, 'Épique', 3, 'Sacrifice (un serviteur allié à 2 HP ou moins) : invoque un Amas Informe 2/2 doté de MUTATION.', 'Chaque offrande revient sous une forme différente.', '/assets/card_art/abomination/pact-of-fresh-flesh.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Rituel de la Chair Qui Recoud', 'Abomination', 'Rituel', NULL, 4, NULL, NULL, 'Rare', 3, 'Éveil : un serviteur Abomination allié aléatoire restaure 2 HP.', 'La chair se répare mal. Elle se répare quand même.', '/assets/card_art/abomination/ritual-of-mending-flesh.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Cavalier des Flammes', 'Demon', 'Serviteur', 'Avant', 4, 4, 3, 'Rare', NULL, 'ASSAUT. Arrivée : ton héros perd 2 HP ; ce serviteur gagne +2/+0 de façon permanente.', 'Sa monture est morte au premier galop. Il n''a pas ralenti pour autant.', '/assets/card_art/demon/flame-rider.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Bourreau des Flammes', 'Demon', 'Serviteur', 'Avant', 4, 5, 3, 'Rare', NULL, 'RAVAGE.', 'Ce qu''il ne peut pas tuer, il l''incendie derrière lui.', '/assets/card_art/demon/flame-executioner.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Fléau Écarlate', 'Demon', 'Rituel', NULL, 4, NULL, NULL, 'Épique', 2, 'Éveil : serviteurs non Démons ennemis -1/-1 ; ton héros perd 1 HP.', 'Le fléau ne fait pas de tri. Il revient juste, patiemment.', '/assets/card_art/demon/crimson-scourge.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Sanctuaire Écarlate', 'Demon', 'Enchantement', NULL, 4, NULL, NULL, 'Épique', NULL, 'Présence : les sorts alliés coûtent 1 de moins (min 1). Ton héros perd 1 HP la première fois que ce rabais s''applique chaque tour.', 'Dans ses murs, la magie coule librement. Rien n''est jamais vraiment gratuit.', '/assets/card_art/demon/crimson-sanctuary.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Fosse Écarlate', 'Demon', 'Enchantement', NULL, 4, NULL, NULL, 'Rare', NULL, 'Appel : si 3 Démons alliés ou plus sont en jeu, invoque une Larve Infernale 2/1.', 'Plus elle se remplit, plus elle déborde de quelque chose d''affamé.', '/assets/card_art/demon/crimson-pit.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Rituel de la Terreur', 'Demon', 'Rituel', NULL, 4, NULL, NULL, 'Épique', 3, 'Deuil : le héros ennemi ne peut pas soigner jusqu''à la fin de son prochain tour.', 'La peur ne referme aucune plaie. C''est précisément le but, encore et encore.', '/assets/card_art/demon/chainmaster.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Marché de Sang', 'Demon', 'Rituel', NULL, 4, NULL, NULL, 'Épique', 3, 'Deuil : ton héros perd 1 HP ; invoque une Larve Infernale 2/1 dotée de PACTE.', 'Chaque offrande en appelle une autre, encore, et encore.', '/assets/card_art/demon/blood-offering.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Grand Prophète Écarlate', 'Demon', 'Serviteur', 'Arriere', 4, 2, 4, 'Épique', NULL, 'CORRUPTION. Arrivée : inflige Corruption à un serviteur ennemi ciblé.', 'Ses visions ne mentent jamais. Elles s''assurent juste de se réaliser.', '/assets/card_art/demon/black-flame-prophet.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Lente Altération', 'Abomination', 'Rituel', NULL, 4, NULL, NULL, 'Épique', 2, 'Éveil : les serviteurs ennemis -1/-1 de façon permanente.', 'Elle ne prépare pas une invasion. Elle prépare une transformation.', '/assets/card_art/abomination/slow-alteration.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Autel de la Souffrance', 'Demon', 'Enchantement', NULL, 4, NULL, NULL, 'Épique', NULL, 'Présence : chaque fois que ton héros perd des HP à cause d''une de tes cartes, tes serviteurs Démons en jeu gagnent +0/+1 jusqu''à la fin du tour.', 'L''autel ne juge pas ce que tu sacrifies. Il se contente d''en redistribuer la force.', '/assets/card_art/demon/altar-of-agony.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Banshee des Abysses', 'Demon', 'Serviteur', 'Arriere', 4, 2, 5, 'Rare', NULL, 'Arrivée : inflige Corruption à un serviteur ennemi ciblé.', 'Son chant ne tue personne. Il fait juste pourrir ce qui l''entend.', '/assets/card_art/demon/abyssal-banshe.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Cercle de Guérison Infernale', 'Demon', 'Rituel', NULL, 4, NULL, NULL, 'Rare', 3, 'Éveil : ton héros regagne 2 HP.', 'Même les Abysses savent qu''un pacte mort ne rapporte plus rien.', '/assets/card_art/demon/abyss-herald.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Rituel du Fil Sous la Peau', 'Abomination', 'Rituel', NULL, 4, NULL, NULL, 'Épique', 3, 'Deuil : un serviteur Abomination allié aléatoire mute immédiatement.', 'Un fil invisible relie chaque chair à sa voisine. Il tire fort, à chaque rupture.', '/assets/card_art/abomination/thread-beneath-the-skin.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Briseur de Horde', 'Humain', 'Serviteur', 'Avant', 4, 4, 3, 'Rare', NULL, 'Assaut : si la cible est un Mort-Vivant, inflige 2 dégâts supplémentaires.', 'Il a perdu son village à la première vague. Il n''a pas perdu la rage.', '/assets/card_art/human/horde-breaker.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Mémorial des Héros', 'Humain', 'Enchantement', NULL, 4, NULL, NULL, 'Épique', NULL, 'Deuil : quand un Humain Légendaire allié meurt, invoque immédiatement un Fantassin Aguerri 2/2 et un Milicien du Bourg 2/1 en rangée Avant.', 'On grave les noms pour ne pas oublier. On continue pour la même raison.', '/assets/card_art/human/hero-memorial.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Résistance Acharnée', 'Humain', 'Rituel', NULL, 4, NULL, NULL, 'Épique', 3, 'Carnage : quand un serviteur ennemi meurt, ton héros regagne 1 HP.', 'Chaque mort laisse quelque chose aux vivants. Quelque chose de dur, de têtu — de précieux.', '/assets/card_art/human/fierce-resistance.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Brise-Mort', 'Humain', 'Serviteur', 'Avant', 4, 4, 3, 'Épique', NULL, 'Arrivée : détruit un serviteur ennemi ressuscité ou réanimé depuis le cimetière ciblé.', NULL, '/assets/card_art/human/deathbreaker.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Fantassin de Contre-Choc', 'Humain', 'Serviteur', 'Avant', 4, 3, 4, 'Rare', NULL, 'CONTRE-ATTAQUE. Blessure : gagne REMPART jusqu''à fin de tour.', 'Chaque coup reçu lui rappelle pourquoi il tient encore debout.', '/assets/card_art/human/countershock-footsoldier.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Monture-et-Cavalier-Ne-Font-Qu''Un', 'Abomination', 'Serviteur', 'Avant', 4, 4, 3, 'Rare', NULL, 'ASSAUT. Arrivée : attaque immédiatement le serviteur ennemi le plus faible en HP, puis mute.', 'On ne sait plus lequel des deux dirige encore l''autre.', '/assets/card_art/abomination/mount-and-rider-as-one.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Cercle de Commandement', 'Humain', 'Enchantement', NULL, 4, NULL, NULL, 'Épique', NULL, 'Éveil : si tu as un Commandant en jeu (carte avec COMMANDEMENT), tous les Humains alliés gagnent +1/+0 ce tour.', 'Un commandant suffit. Le cercle fait le reste.', '/assets/card_art/human/command-circle.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Ce Qu''on a Laissé Pousser', 'Abomination', 'Enchantement', NULL, 5, NULL, NULL, 'Épique', NULL, 'Deuil : invoque 2 Abominations aléatoires de coût ≤3 ; elles mutent immédiatement.', 'On l''a érigé pour se souvenir des disparus. Il préfère les remplacer.', '/assets/card_art/abomination/allowed-growth.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('La Faim Cuirassée', 'Abomination', 'Serviteur', 'Avant', 5, 6, 4, 'Épique', NULL, 'RAVAGE. ASSIMILATION.', 'Chaque mort autour d''elle l''épaissit un peu plus.', '/assets/card_art/abomination/armored-hunger.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Cercle de Convocation', 'Mort-Vivant', 'Rituel', NULL, 5, NULL, NULL, 'Épique', 3, 'Éveil : invoque un Mort-Vivant aléatoire de coût ≤2 gratuitement.', 'Le cercle appelle. Les morts n''ont pas appris à décliner.', '/assets/card_art/undead/circle-of-summoning.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Symbiose Infernale', 'Demon', 'Enchantement', NULL, 5, NULL, NULL, 'Épique', NULL, 'Présence : tes serviteurs en rangée Arrière gagnent +0/+1 par serviteur Démon allié en rangée Avant.', 'Ceux de devant brûlent. Ceux de derrière se nourrissent de la chaleur.', '/assets/card_art/demon/infernal-symbiosis.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Lien Sans Membrane', 'Abomination', 'Enchantement', NULL, 5, NULL, NULL, 'Épique', NULL, 'Présence : tes serviteurs en rangée Arrière gagnent +0/+1 par serviteur Abomination allié en rangée Avant.', 'Ceux de devant absorbent. Ceux de derrière en profitent.', '/assets/card_art/abomination/bond-without-membrane.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Faucheur des Abysses', 'Demon', 'Serviteur', 'Avant', 5, 5, 5, 'Épique', NULL, 'Arrivée : détruit tous les serviteurs ennemis ayant 3 HP ou moins ; ton héros perd 2 HP.', 'Il choisit les plus faibles. Toi, tu paies pour son jugement.', '/assets/card_art/demon/abyss-reaper.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Forteresse Imprenable', 'Humain', 'Enchantement', NULL, 5, NULL, NULL, 'Épique', NULL, 'Carnage ennemi : chaque fois qu''un serviteur ennemi meurt, tes serviteurs en rangée Avant gagnent +0/+1 jusqu''à fin de tour.', 'Chaque ennemi abattu consolide ce qui reste debout.', '/assets/card_art/human/impregnable-fortress.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Rituel de la Forme Jamais Fixée', 'Abomination', 'Rituel', NULL, 5, NULL, NULL, 'Épique', 3, 'Éveil : un serviteur Abomination allié aléatoire mute immédiatement.', 'Le cercle ne s''arrête jamais de proposer de nouvelles formes.', '/assets/card_art/abomination/ritual-of-shifting-form.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Cœur du Gouffre', 'Demon', 'Enchantement', NULL, 5, NULL, NULL, 'Épique', NULL, 'Présence : au début de ton tour, ton héros perd 1 HP ; tous tes serviteurs Démons gagnent +1/+0 jusqu''à la fin du tour.', 'Il bat au rythme de ce que tu es prêt à sacrifier chaque matin.', '/assets/card_art/demon/heart-of-the-chasm.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Rituel de Résurrection', 'Mort-Vivant', 'Rituel', NULL, 5, NULL, NULL, 'Épique', 2, 'Éveil : ressuscite le dernier Mort-Vivant allié mort avec 1 HP en rangée Avant.', 'Le cercle ne ferme jamais complètement. C''est voulu.', '/assets/card_art/undead/resurection-ritual.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Grand Inquisiteur du Sang', 'Demon', 'Serviteur', 'Avant', 5, 3, 5, 'Épique', NULL, 'SANG NOIR. RANG INFERNAL.', 'Plus tu payes, plus il devient difficile à ignorer.', '/assets/card_art/demon/grand-blood-inquisitor.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Contre-Attaque Générale', 'Humain', 'Rituel', NULL, 5, NULL, NULL, 'Épique', 2, 'Blessure : chaque serviteur Humain allié qui subit des dégâts et survit inflige son ATK en retour à l''attaquant.', 'Chaque coup reçu est une réponse en attente.', '/assets/card_art/human/general-counterattack.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Titan de Cendres', 'Demon', 'Serviteur', 'Avant', 5, 4, 6, 'Rare', NULL, 'REMPART. Dernier Souffle : ton héros perd 2 HP ; inflige 3 dégâts au héros adverse.', 'Sa chute n''éteint rien. Elle propage juste l''incendie ailleurs.', '/assets/card_art/demon/ash-titan.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Ravageur Putréfié', 'Mort-Vivant', 'Serviteur', 'Avant', 5, 6, 4, 'Épique', NULL, 'RAVAGE. Mort-rage : serviteurs Mort-Vivants alliés +2/+2.', 'Chaque mort nourrit sa rage. Et il y a toujours de nouveaux morts.', '/assets/card_art/undead/putrefied-ravager.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Faucheur de la Plaie', 'Mort-Vivant', 'Serviteur', 'Avant', 5, 5, 5, 'Épique', NULL, 'Arrivée : détruit tous les serviteurs ennemis ayant 3 HP ou moins.', 'Il ne choisit pas les plus forts. Il choisit les presque morts — pour finir le travail.', '/assets/card_art/undead/plague-reaper.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Trône de Cendres', 'Demon', 'Serviteur', 'Avant', 5, 3, 8, 'Épique', NULL, 'REMPART. RANG INFERNAL.', 'Il siège sur ce que ton héros a déjà perdu.', '/assets/card_art/demon/ashen-throne.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Bannière du Roi', 'Humain', 'Rituel', NULL, 5, NULL, NULL, 'Épique', 2, 'Éveil : si tu as un Humain Légendaire en jeu, invoque un Fantassin Aguerri 2/2 en rangée Avant.', 'Sous cette bannière, on ne compte plus les morts. On compte ceux qui restent debout.', '/assets/card_art/human/kings-banner.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Cimetière Vivant', 'Mort-Vivant', 'Enchantement', NULL, 5, NULL, NULL, 'Épique', NULL, 'Deuil : ce Mort-Vivant revient en jeu à la fin du tour avec 1 HP. (Une seule fois par serviteur.)', 'Le sol ici ne garde rien. Il régurgite.', '/assets/card_art/undead/living-cemetery.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Code du Chevalier', 'Humain', 'Rituel', NULL, 5, NULL, NULL, 'Épique', 3, 'Résonance : chaque fois qu''un serviteur Humain allié attaque, tous tes serviteurs alliés gagnent +1 ATK de façon permanente.', 'L''honneur ne protège pas. Mais il donne un tranchant supplémentaire.', '/assets/card_art/human/knight-code.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Fortification des Lignes', 'Humain', 'Rituel', NULL, 5, NULL, NULL, 'Rare', 3, 'Éveil : si ta rangée Avant a 5 serviteurs ou plus, ils gagnent tous REMPART jusqu''à fin de tour.', 'Cinq hommes côte à côte. Ça devient quelque chose d''autre. Quelque chose qui ne cède pas.', '/assets/card_art/human/line-fortification.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Cercle de l''Assemblage', 'Abomination', 'Rituel', NULL, 5, NULL, NULL, 'Épique', 2, 'Sacrifice (deux serviteurs alliés) : un allié restant aléatoire gagne +2/+2 de façon permanente.', 'Deux corps entrent. Un seul en ressort — plus grand.', '/assets/card_art/abomination/circle-of-assembly.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Monument aux Morts', 'Mort-Vivant', 'Enchantement', NULL, 5, NULL, NULL, 'Épique', NULL, 'Deuil : invoque 2 Mort-Vivants aléatoires de coût ≤3.', 'On l''a érigé pour honorer les disparus. Il préfère les renvoyer.', '/assets/card_art/undead/monument-of-death.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Maréchal de Campagne', 'Humain', 'Serviteur', 'Arriere', 5, 2, 5, 'Épique', NULL, 'COMMANDEMENT. Éveil : tous les serviteurs Humains alliés gagnent +1/+0 jusqu''à fin de tour.', 'Il ne crie pas les ordres. Il les dit une fois, calmement. Ça suffit.', '/assets/card_art/human/campaign-marshal.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Général de Brigade', 'Humain', 'Serviteur', 'Arriere', 5, 3, 4, 'Épique', NULL, 'COMMANDEMENT. Éveil : invoque un Fantassin Aguerri 2/2 en rangée Avant si tu as 4 Humains ou plus en jeu.', 'Une armée n''est pas un nombre. C''est une volonté. La sienne.', '/assets/card_art/human/brigade-general.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Inquisiteur Suprême', 'Humain', 'Serviteur', 'Hybride', 5, 3, 5, 'Épique', NULL, 'DISCIPLINE. Arrivée : annule tous les effets Infection sur tes serviteurs alliés.', 'La corruption s''arrête là où il pose le regard.', '/assets/card_art/human/supreme-inquisitor.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Chevalier de la Contre-Marche', 'Humain', 'Serviteur', 'Avant', 5, 4, 5, 'Épique', NULL, 'CONTRE-ATTAQUE. ASSAUT. Blessure : gagne +2/+0 jusqu''à fin de tour.', 'Il charge. Il encaisse. Il charge encore. C''est tout ce qu''il sait faire — et c''est suffisant.', '/assets/card_art/human/countermarch-knight.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Paladin de l''Aube', 'Humain', 'Serviteur', 'Avant', 5, 4, 5, 'Épique', NULL, 'ÉGIDE. MOISSON. Arrivée : invoque un Éclaireur Rapide 1/1 en rangée Avant.', 'Il arrive à l''aube. Les morts reculent à la lumière. Lui aussi en a été surpris, la première fois.', '/assets/card_art/human/dawn-paladin.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Le Trieur de Chairs', 'Abomination', 'Serviteur', 'Avant', 5, 5, 5, 'Épique', NULL, 'Arrivée : détruit un serviteur ennemi ayant 3 HP ou moins, puis mute.', 'Il ne choisit pas ses proies. Il choisit ce qu''il veut devenir ensuite.', '/assets/card_art/abomination/flesh-sorter.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('La Terre Qui Refuse de Garder', 'Abomination', 'Enchantement', NULL, 5, NULL, NULL, 'Épique', NULL, 'Deuil : le serviteur allié mort revient immédiatement en jeu.', 'Le sol ici ne garde rien. Il rend, mais jamais tel quel.', '/assets/card_art/abomination/unkeeping-earth.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Ce-Qui-A-Cessé-de-S''arrêter', 'Abomination', 'Serviteur', 'Avant', 5, 3, 8, 'Épique', NULL, 'REMPART. ASSIMILATION. Dernier Souffle : invoque 3 Amas Informes 1/2 en rangée Avant.', 'Elle n''était pas un monstre. Elle était une croissance qu''on a laissée trop longtemps.', '/assets/card_art/abomination/unstopping.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Tombeau Ambulant', 'Mort-Vivant', 'Serviteur', 'Avant', 5, 3, 8, 'Épique', NULL, 'REMPART. Dernier Souffle : invoque 3 Rampants 1/1 en rangée Avant.', 'Il n''était pas un monstre. Il était une fosse commune.', '/assets/card_art/undead/walking-tomb.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Rituel du Pacte Éternel', 'Demon', 'Rituel', NULL, 5, NULL, NULL, 'Épique', 3, 'Éveil : ton héros perd 1 HP ; invoque une Larve Infernale 2/1 en rangée Avant.', 'Le pacte ne se referme jamais. C''est écrit dans les clauses les plus petites.', '/assets/card_art/demon/summoning-circle.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Temple de Guerre', 'Humain', 'Enchantement', NULL, 5, NULL, NULL, 'Épique', NULL, 'Appel : chaque serviteur allié invoqué gagne +1/+1 de façon permanente.', 'On ne vient pas y prier. On vient y apprendre à tenir sa place dans la ligne.', '/assets/card_art/human/war-temple.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Ordre des Anciens', 'Humain', 'Enchantement', NULL, 5, NULL, NULL, 'Épique', NULL, 'Éveil : si tu as 5 Humains ou plus en jeu, invoque un Capitaine de Milice 3/3 en rangée Avant.', 'Les anciens ne reviennent pas par magie. Ils reviennent parce qu''on a encore besoin d''eux.', '/assets/card_art/human/order-of-ancients.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Ravageur des Flammes', 'Demon', 'Serviteur', 'Avant', 5, 6, 4, 'Épique', NULL, 'RAVAGE. RANG INFERNAL.', 'Plus ton héros saigne, plus il brûle fort.', '/assets/card_art/demon/inferno-ravager.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Symbiose Cadavérique', 'Mort-Vivant', 'Enchantement', NULL, 5, NULL, NULL, 'Épique', NULL, 'Présence : tes serviteurs en rangée Arrière gagnent +0/+1 par serviteur allié en rangée Avant.', 'Les morts de devant protègent les morts de derrière. C''est le seul lien qui reste.', '/assets/card_art/undead/cadaverous-simbiosis.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Ce-Qui-A-Trop-Poussé', 'Abomination', 'Serviteur', 'Avant', 5, 4, 6, 'Rare', NULL, 'REMPART. MUTATION.', 'On l''a vu changer trois fois dans la même bataille.', '/assets/card_art/abomination/overgrowth.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Aegis de l''Empire', 'Humain', 'Enchantement', NULL, 5, NULL, NULL, 'Légendaire', NULL, 'Présence : tes serviteurs Humains en rangée Avant sont immunisés à l''Infection. Les marqueurs Infection déjà présents sont retirés à la fin de chaque tour.', 'L''Empire ne cède pas à la pourriture. Ce n''est pas de l''orgueil. C''est de l''obstination.', '/assets/card_art/human/empire-aegis.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Exécuteur de l''Ordre', 'Humain', 'Serviteur', 'Avant', 5, 5, 4, 'Épique', NULL, 'VENIN MORTEL. DISCIPLINE. Ne peut attaquer que les serviteurs (jamais le héros directement).', 'Il n''a pas de haine. Il a des instructions. C''est pire.', '/assets/card_art/human/order-executioner.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Géant Boursouflé', 'Mort-Vivant', 'Serviteur', 'Avant', 5, 4, 6, 'Rare', NULL, 'Dernier Souffle : inflige 2 dégâts à tous les serviteurs ennemis en rangée Avant.', 'Sa mort est plus dangereuse que sa vie.', '/assets/card_art/undead/bloated-giant.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Cercle de Corruption', 'Demon', 'Rituel', NULL, 5, NULL, NULL, 'Épique', 3, 'Éveil : inflige Corruption à un serviteur ennemi aléatoire.', 'Le cercle ne choisit pas. Il se contente de continuer.', '/assets/card_art/demon/scourge-of-kingdoms.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Rituel de la Fosse Sans Fond', 'Mort-Vivant', 'Rituel', NULL, 6, NULL, NULL, 'Épique', 2, 'Sacrifice (un serviteur allié) : pioche 1 carte.', 'Il a tout donné. Il savait exactement ce que ça valait — un peu à la fois.', '/assets/card_art/undead/ritual-of-the-bottomless-pit.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Puits Qui Avale Tout', 'Abomination', 'Enchantement', NULL, 6, NULL, NULL, 'Légendaire', NULL, 'Dévoration : gagne 1 mana temporaire ce tour (une seule fois par tour).', 'Tout ce qui meurt ici finit par nourrir autre chose.', '/assets/card_art/abomination/all-swallowing-well.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Rituel de l''Œil Sans Sommeil', 'Abomination', 'Rituel', NULL, 6, NULL, NULL, 'Légendaire', 2, 'Sortilège ennemi : annulé s''il cible un de tes Abominations.', 'Il ne dort jamais. Il voit venir la magie adverse avant qu''elle n''arrive.', '/assets/card_art/abomination/sleepless-eye-ritual.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Rituel du Ventre Qui Prend Tout', 'Abomination', 'Rituel', NULL, 6, NULL, NULL, 'Épique', 2, 'Sacrifice (un serviteur allié) : pioche 1 carte ; ton héros regagne des HP.', 'Rien ne se perd vraiment. Tout se redistribue, même à toi.', '/assets/card_art/abomination/all-devouring-belly.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Rituel de l''Éclipse', 'Mort-Vivant', 'Rituel', NULL, 6, NULL, NULL, 'Légendaire', 2, 'Sortilège ennemi : annulé s''il cible un de tes Mort-Vivants.', 'Sous l''éclipse, la magie adverse perd ses repères. Les morts, eux, n''en ont plus besoin.', '/assets/card_art/undead/ritual-of-the-eclipse.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('L''Éternel Recommencement', 'Abomination', 'Serviteur', 'Arriere', 6, 0, 4, 'Légendaire', NULL, 'Éveil : invoque une Abomination aléatoire de coût ≤3 en rangée Avant ; elle mute immédiatement.', 'Il ne se soigne plus. Il se réinvente, sans fin.', '/assets/card_art/abomination/the-eternal-beginning.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Vortex des Âmes', 'Mort-Vivant', 'Enchantement', NULL, 6, NULL, NULL, 'Légendaire', NULL, 'Carnage : gagne 1 mana temporaire ce tour.', 'Les âmes qui s''y perdent alimentent quelque chose que personne ne comprend vraiment.', '/assets/card_art/undead/vortex-of-souls.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Le Médecin de la Peste', 'Mort-Vivant', 'Serviteur', 'Arriere', 6, 0, 4, 'Légendaire', NULL, 'Éveil : invoque un Mort-Vivant aléatoire de coût ≤3 en rangée Avant.', 'Il soignait les vivants autrefois. Il a simplement changé de patientèle.', '/assets/card_art/undead/plague-emissary.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Mur Infranchissable', 'Humain', 'Rituel', NULL, 6, NULL, NULL, 'Épique', 2, 'Sortilège ennemi : annulé s''il cible un serviteur Humain allié en rangée Avant.', 'La magie s''arrête là où la volonté commence.', '/assets/card_art/human/impassable-wall.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Rituel du Gouffre Sans Fond', 'Demon', 'Rituel', NULL, 6, NULL, NULL, 'Épique', 2, 'Sacrifice (un serviteur allié) : pioche 1 carte ; ton héros regagne 1 HP.', 'Le seul rituel démoniaque qui rend plus qu''il ne prend — tant qu''il reste des charges.', '/assets/card_art/demon/bottomless-abyss-ritual.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Purge Sainte', 'Humain', 'Rituel', NULL, 6, NULL, NULL, 'Légendaire', 2, 'Éveil : détruit les serviteurs Mort-Vivants ennemis ayant 3 HP ou moins.', 'Ce n''est pas une prière. C''est une déclaration.', '/assets/card_art/human/holy-purge.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Cercle de Sacrifice', 'Mort-Vivant', 'Rituel', NULL, 6, NULL, NULL, 'Légendaire', 2, 'Sacrifice (un serviteur allié) : tes serviteurs restants gagnent +1/+1 jusqu''à la fin du tour.', 'Le cercle ne se lasse pas de demander. Il attend juste la prochaine offrande.', '/assets/card_art/undead/circle-of-sacrifice.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Colosse Décomposé', 'Mort-Vivant', 'Serviteur', 'Avant', 6, 7, 7, 'Épique', NULL, 'REMPART. CHAIR MORTE. Immunisé au débordement de RAVAGE : les dégâts excédentaires ne se propagent jamais sur ton héros.', 'Les lames disparaissent dans sa masse. Il continue d''avancer.', '/assets/card_art/undead/decayed-colossus.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Le Gardien du Pacte Brisé', 'Demon', 'Serviteur', 'Arriere', 6, 5, 7, 'Légendaire', NULL, 'Tant que ce serviteur est en jeu, les dégâts que tes propres cartes infligent à ton héros sont annulés.', 'Il a lu chaque clause du contrat. Il a décidé qu''aucune ne s''appliquerait plus.', '/assets/card_art/demon/keeper-of-the-broken-pact.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Ce-Qui-N''a-Plus-de-Bords', 'Abomination', 'Serviteur', 'Avant', 6, 7, 7, 'Épique', NULL, 'REMPART. INSTABLE. MUTATION.', 'On ne sait plus où il s''arrête, ni s''il s''arrête vraiment.', '/assets/card_art/abomination/edgeless.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Rituel de l''Éclipse Rouge', 'Demon', 'Rituel', NULL, 6, NULL, NULL, 'Légendaire', 3, 'Sortilège ennemi : annulé s''il cible un de tes Démons ; ton héros perd 1 HP à chaque annulation.', 'Sous cette éclipse, même se protéger a un prix, à répétition.', '/assets/card_art/demon/ritual-of-the-crimson-eclipse.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Idole du Grand Pacte', 'Demon', 'Enchantement', NULL, 6, NULL, NULL, 'Légendaire', NULL, 'Résonance : le Démon attaquant inflige 1 dégât splash aux serviteurs adjacents à la cible ; ton héros perd 1 HP.', 'On ne l''a pas sculptée. Elle a simplement accepté de rester.', '/assets/card_art/demon/grand-pact-idol.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Le Marchand d''Âmes', 'Demon', 'Serviteur', 'Arriere', 6, 0, 4, 'Légendaire', NULL, 'Éveil : ton héros perd 1 HP ; pioche 1 carte.', 'Il ne se bat pas. Il n''en a pas besoin — le contrat travaille pour lui, tour après tour.', '/assets/card_art/demon/soul-merchant.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Le Rempart Vivant', 'Humain', 'Serviteur', 'Avant', 6, 4, 10, 'Légendaire', NULL, 'REMPART. FORTIFICATION. CONTRE-ATTAQUE. Blessure : invoque un Porteur de Bouclier 1/4 REMPART.', 'On lui a demandé combien de temps il pouvait tenir. Il n''a pas répondu. Il tient encore.', '/assets/card_art/human/living-rampart.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Cercle de Dégénérescence', 'Abomination', 'Rituel', NULL, 6, NULL, NULL, 'Légendaire', 2, 'Sacrifice (un serviteur allié) : tous les serviteurs ennemis en rangée Avant subissent une mutation forcée : Dégénérescence.', 'Ce que le cercle ne peut pas améliorer, il le corrompt.', '/assets/card_art/abomination/circle-of-degeneration.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Idole de l''Apocalypse', 'Mort-Vivant', 'Enchantement', NULL, 6, NULL, NULL, 'Légendaire', NULL, 'Résonance : chaque Mort-Vivant attaquant inflige 1 dégât aux serviteurs adjacents à la cible.', 'On ne l''a pas sculpté. On l''a trouvé ainsi, debout, au milieu des ruines.', '/assets/card_art/undead/idol-of-the-apocalypse.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Décret Royal', 'Humain', 'Enchantement', NULL, 6, NULL, NULL, 'Légendaire', NULL, 'Éveil : tous tes serviteurs Humains gagnent +1/+1. (S''accumule chaque tour.)', 'Le décret n''a pas de date d''expiration. La guerre non plus.', '/assets/card_art/human/royal-decree.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Effigie Née d''Elle-Même', 'Abomination', 'Enchantement', NULL, 6, NULL, NULL, 'Légendaire', NULL, 'Résonance : le serviteur Abomination attaquant inflige 1 dégât splash aux serviteurs adjacents à la cible.', 'On ne l''a pas sculptée. Elle a poussé, un jour, et personne ne l''a arrêtée.', '/assets/card_art/abomination/self-born-effigy.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Cercle du Grand Pacte', 'Demon', 'Rituel', NULL, 6, NULL, NULL, 'Légendaire', 2, 'Sacrifice (un serviteur allié) : tes serviteurs restants gagnent +1/+1 jusqu''à la fin du tour ; ton héros perd 1 HP.', 'Le cercle ne se lasse pas de demander. Il attend juste la prochaine offrande.', '/assets/card_art/demon/crown-of-the-pact.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('La Grande Inquisitrice', 'Humain', 'Serviteur', 'Arriere', 6, 3, 6, 'Légendaire', NULL, 'DISCIPLINE. Éveil : détruit un enchantement ou rituel ennemi actif aléatoire.', 'Elle ne combat pas la magie ennemie. Elle la refuse.', '/assets/card_art/human/grand-inquisitrix.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Vortex des Damnés', 'Demon', 'Enchantement', NULL, 6, NULL, NULL, 'Légendaire', NULL, 'Carnage : gagne 1 mana temporaire ce tour ; ton héros perd 1 HP.', 'Les âmes qui s''y perdent paient toujours un peu plus que prévu.', '/assets/card_art/demon/vortex-of-the-damned.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('L''Innommable', 'Abomination', 'Serviteur', 'Avant', 7, 7, 6, 'Légendaire', NULL, 'Arrivée : choisis un serviteur ennemi ciblé — il devient une copie exacte (stats et mots-clés) sous ton contrôle jusqu''à la fin de la partie.', 'Il n''a pas de visage. Il porte le tien, à présent.', '/assets/card_art/abomination/the-nameless.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Ce-Qui-Se-Souvient-Par-le-Corps', 'Abomination', 'Serviteur', 'Avant', 7, 6, 8, 'Légendaire', NULL, 'Arrivée : gagne +3/+3 de façon permanente.', 'Il n''a pas de mémoire. Il a une chair qui se souvient à sa place.', '/assets/card_art/abomination/flesh-memory.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('La Faucheuse', 'Mort-Vivant', 'Serviteur', 'Avant', 7, 7, 6, 'Légendaire', NULL, 'Arrivée : détruit un serviteur ennemi ciblé et le ressuscite sous ton contrôle sans ses effets.', 'Elle ne prend pas les âmes. Elle redistribue les corps.', '/assets/card_art/undead/the-reaper.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Le Grand Pacte', 'Demon', 'Serviteur', 'Avant', 7, 7, 6, 'Légendaire', NULL, 'PACTE. Arrivée : ton héros perd 3 HP supplémentaires ; détruit un serviteur ennemi ciblé.', 'Il ne demande jamais la permission. Il constate simplement ce que tu es prêt à perdre.', '/assets/card_art/demon/the-grand-pact.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Roi Liche Zombie', 'Mort-Vivant', 'Serviteur', 'Avant', 7, 6, 8, 'Légendaire', NULL, 'Arrivée : ressuscite les 3 derniers Mort-Vivants alliés morts ce match avec 1 HP en rangée Avant.', 'Son royaume n''a pas de frontières. Il s''étend à mesure que ses sujets meurent.', '/assets/card_art/undead/zombie-lich-king.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Éclosion Sans Fin', 'Abomination', 'Rituel', NULL, 7, NULL, NULL, 'Légendaire', 3, 'Éveil : invoque une Abomination aléatoire de coût ≤4 ; elle mute deux fois.', 'Elle n''a pas éclos une fois. Elle éclot encore.', '/assets/card_art/abomination/endless-hatching.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Le Roi Soldat', 'Humain', 'Serviteur', 'Avant', 7, 6, 8, 'Légendaire', NULL, 'COMMANDEMENT. ÉGIDE. Arrivée : tous les serviteurs Humains alliés gagnent +2/+2 de façon permanente.', 'Il n''a pas pris la couronne. On la lui a posée sur le champ de bataille, entre deux assauts.', '/assets/card_art/human/soldier-king.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Ce-Qui-Ne-Finit-Jamais-de-Grandir', 'Abomination', 'Serviteur', 'Avant', 7, 8, 10, 'Légendaire', NULL, 'REMPART. Une masse qui a cessé de compter ses métamorphoses.', 'Il a arrêté de compter ses formes il y a longtemps.', '/assets/card_art/abomination/endless-growth.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Léviathan Putréfié', 'Mort-Vivant', 'Serviteur', 'Avant', 7, 8, 10, 'Légendaire', NULL, 'REMPART. Arrivée : serviteurs Mort-Vivants alliés +2/+2.', 'Les mers l''ont recraché. Elles non plus ne voulaient plus de lui.', '/assets/card_art/undead/putrefied-leviathan.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Arrivée de Masse', 'Mort-Vivant', 'Rituel', NULL, 7, NULL, NULL, 'Légendaire', 3, 'Éveil : invoque un Mort-Vivant aléatoire de coût ≤4.', 'Il n''a pas ouvert une porte. Il a retiré le mur.', '/assets/card_art/undead/mass-invocation.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Commandant des Derniers', 'Humain', 'Serviteur', 'Avant', 7, 5, 6, 'Légendaire', NULL, 'COMMANDEMENT. Dernier Souffle : ressuscite jusqu''à 5 serviteurs Humains alliés morts avec 1 HP en rangée Avant.', 'Sa mort n''est pas une fin. C''est un dernier ordre.', '/assets/card_art/human/last-commander.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Roi Démon Écarlate', 'Demon', 'Serviteur', 'Avant', 7, 6, 8, 'Légendaire', NULL, 'CORRUPTION. Arrivée : ton héros perd 3 HP ; inflige Corruption à tous les serviteurs ennemis.', 'Son royaume ne s''étend pas par la conquête. Il s''étend par ce qu''il te fait accepter.', '/assets/card_art/demon/crimson-demon-king.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Invasion Écarlate', 'Demon', 'Rituel', NULL, 7, NULL, NULL, 'Légendaire', 3, 'Éveil : invoque un Démon aléatoire de coût ≤4 ; ton héros perd 1 HP.', 'Ils ne demandent pas la permission d''entrer. Ils reviennent, simplement, tour après tour.', '/assets/card_art/demon/crimson-invasion.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('L''Éternel Gardien', 'Humain', 'Serviteur', 'Avant', 8, 7, 9, 'Légendaire', NULL, 'REMPART. ÉGIDE. DISCIPLINE. Arrivée : tous les serviteurs ennemis perdent leurs mots-clés jusqu''à la fin du prochain tour adverse.', 'Il n''a pas survécu à toutes ces guerres par chance. Il a survécu parce que rien de ce que l''ennemi fait ne le surprend.', '/assets/card_art/human/eternal-guardian.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Grand Retour Sous une Autre Forme', 'Abomination', 'Rituel', NULL, 8, NULL, NULL, 'Légendaire', 3, 'Deuil : ramène en main le serviteur Abomination allié le plus récemment mort.', '"Je ne les rappelle pas. Je les laisse simplement finir de devenir autre chose."', '/assets/card_art/abomination/reshaped-return.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Apocalypse Infernale', 'Demon', 'Serviteur', 'Avant', 8, 9, 9, 'Légendaire', NULL, 'RANG INFERNAL. Arrivée : ton héros perd 5 HP ; tous tes serviteurs Démons gagnent +2/+2 de façon permanente.', 'Ce n''était pas une invasion. C''était le prix qu''il fallait payer.', '/assets/card_art/demon/infernal-apocalypse.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('La Grande Contamination', 'Abomination', 'Serviteur', 'Avant', 8, 9, 9, 'Légendaire', NULL, 'Arrivée : détruit tous les serviteurs ennemis en jeu.', 'Ce n''était pas une invasion. C''était une contamination.', '/assets/card_art/abomination/great-contamination.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Grand Rituel du Pacte', 'Demon', 'Rituel', NULL, 8, NULL, NULL, 'Légendaire', 3, 'Deuil : ramène en main le Démon allié le plus récemment mort ; ton héros perd 1 HP.', 'Je ne les ai pas ressuscités. Je les rappelle, un par un, à chaque fois qu''il le faut.', '/assets/card_art/demon/grand-pact-ritual.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Grand Rituel Nécrotique', 'Mort-Vivant', 'Rituel', NULL, 8, NULL, NULL, 'Légendaire', 3, 'Deuil : ramène en main le Mort-Vivant allié le plus récemment mort.', NULL, '/assets/card_art/undead/grand-necrotic-ritual.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Grande Mobilisation', 'Humain', 'Rituel', NULL, 8, NULL, NULL, 'Légendaire', 3, 'Éveil : invoque un Humain aléatoire de coût ≤4 en rangée Avant.', 'Quand tout le reste a échoué, il reste les hommes. Il y en a toujours assez pour une dernière fois.', '/assets/card_art/human/great-mobilization.jpg');
INSERT INTO cards (name, race, card_type, lane, cost, attack, hp, rarity, charges, effect, flavor, image_path) VALUES ('Apocalypse Zombie', 'Mort-Vivant', 'Serviteur', 'Avant', 8, 9, 9, 'Légendaire', NULL, 'Arrivée : transforme tous les serviteurs adverses en jeu en Zombies 1/1 sous ton contrôle.', 'Ce n''était pas une invasion. C''était une conversion.', '/assets/card_art/undead/zombie-apocalypse.jpg');
